```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { registerDestructor } from '@ember/destroyable'

export default class LiveFeedComponent extends Component {
  constructor(owner, args) {
    super(owner, args)
    // Cancel all when component is destroyed
    registerDestructor(this, () => this.pollScore.cancelAll())
  }

  pollScore = task(async () => {
    while (true) {
      const response = await fetch('/api/live-score')
      const data = await response.json()
      // process data...
      await timeout(5000)
    }
  })

  stopPolling = () => {
    this.pollScore.cancelAll()
  }

  <template>
    <button {{on 'click' this.pollScore.perform}}>Start</button>
    <button {{on 'click' this.stopPolling}}>Stop</button>
  </template>
}
```
`task.cancelAll()` immediately cancels all currently running instances of that task. It returns a Promise that resolves when all instances have been cancelled. This is essential for cleanup — especially for polling tasks or long-running operations — and should be called in `willDestroy` or via `registerDestructor` to prevent memory leaks.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class MatchComponent extends Component {
  fetchMatch = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}`)
    return response.json()
  })

  logLastInstance = () => {
    const lastInstance = this.fetchMatch.last
    if (lastInstance) {
      console.log('State:', lastInstance.isRunning, lastInstance.isFinished)
      console.log('Value:', lastInstance.value)
      console.log('Error:', lastInstance.error)
    }
  }

  <template>
    <button {{on 'click' (fn this.fetchMatch.perform 'match-1')}}>Fetch</button>
    {{#if this.fetchMatch.last}}
      <p>Last run finished: {{this.fetchMatch.last.isFinished}}</p>
    {{/if}}
  </template>
}
```
`task.last` returns the most recently created task instance (TaskInstance). It is `null` before the first `.perform()` call. Through `task.last`, you can inspect the instance's state (`isRunning`, `isFinished`, `isCanceled`), its resolved `value`, or its `error`. This is the primary way to access results from the last execution.

