import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class MultiTaskDemo extends Component {
  @tracked score = null
  @tracked searchResults = []
  @tracked draftSaved = false

  // drop: ignore repeated clicks while running
  fetchScore = task({ drop: true }, async () => {
    const res = await fetch(`/api/matches/${this.args.matchId}/score`)
    this.score = await res.json()
  })

  // restartable: restart on each new keystroke (debounced search)
  searchPlayers = task({ restartable: true }, async (query) => {
    await timeout(300)
    const res = await fetch(`/api/players?q=${query}`)
    this.searchResults = await res.json()
  })

  // keepLatest: queue the latest change but don't run concurrently
  saveDraft = task({ keepLatest: true }, async (draft) => {
    await timeout(500)
    await fetch('/api/drafts', {
      method: 'PUT',
      body: JSON.stringify(draft),
      headers: { 'Content-Type': 'application/json' },
    })
    this.draftSaved = true
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchScore.perform)}}>Score</button>
    <input type="search" {{on "input" (fn this.searchPlayers.perform value="target.value")}} />
    {{#if this.score}}<p>{{this.score.runs}}/{{this.score.wickets}}</p>{{/if}}
    {{#if this.draftSaved}}<p class="text-green-500">Draft saved</p>{{/if}}
  </template>
}
```
Each modifier targets a different UX problem: `drop` for idempotent actions where duplicate calls are wasteful, `restartable` for live filtering where only the latest input matters, and `keepLatest` for save operations where you always want the final state persisted but don't want concurrent writes.

