// Wrap localStorage in Promises to make it task-compatible
const readStorage = (key) =>
  new Promise((resolve) => {
    const value = localStorage.getItem(key)
    resolve(value ? JSON.parse(value) : null)
  })

const writeStorage = (key, value) =>
  new Promise((resolve) => {
    localStorage.setItem(key, JSON.stringify(value))
    resolve()
  })

export default class FavoriteTeams extends Component {
  @tracked favorites = []

  loadFavorites = task(async () => {
    const stored = await readStorage('spordium:favorite-teams')
    this.favorites = stored ?? []
  })

  saveFavorite = task({ keepLatest: true }, async (team) => {
    const updated = [...this.favorites, team]
    await writeStorage('spordium:favorite-teams', updated)
    this.favorites = updated
  })

  <template>
    <div {{did-insert (fn this.loadFavorites.perform)}}>
      <h3>Favorite Teams</h3>
      <ul>
        {{#each this.favorites as |team|}}
          <li>{{team.name}}</li>
        {{/each}}
      </ul>
    </div>
  </template>
}
