    {{else if this.matchData}}
      <h2>{{this.matchData.title}}</h2>
      <p>Venue: {{this.matchData.venue}}</p>
      <p>Date: {{this.matchData.scheduledAt}}</p>
    {{/if}}
  </template>
}
