import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MultiSourceScoreComponent extends Component {
  @tracked scores = []
  @tracked errors = []

  fetchAllScores = task(async (matchId) => {
    const sources = [
      fetch(`/api/primary/scores/${matchId}`).then((r) => r.json()),
      fetch(`/api/backup/scores/${matchId}`).then((r) => r.json()),
      fetch(`/api/third-party/scores/${matchId}`).then((r) => r.json()),
    ]
    const results = await Promise.allSettled(sources)
    this.scores = results
      .filter((r) => r.status === 'fulfilled')
      .map((r) => r.value)
    this.errors = results
      .filter((r) => r.status === 'rejected')
      .map((r) => r.reason.message)
    return this.scores
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchAllScores.perform @matchId)}}>
      Fetch All Sources
    </button>
    {{#each this.errors as |err|}}
      <p class="text-yellow-600">Warning: {{err}}</p>
    {{/each}}
    {{#each this.scores as |score|}}
      <p>Source score: {{score.runs}}/{{score.wickets}}</p>
    {{/each}}
  </template>
}
```

`Promise.allSettled` never short-circuits — it waits for all Promises regardless of whether some fail. The task filters the results array by `status` to separate successful scores from errors. This pattern is ideal for a sports data app that aggregates from multiple score providers where partial data is still useful.

