import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class AllMatchesComponent extends Component {
  @tracked allMatches = []

  fetchAllMatches = task(async (tournament) => {
    let page = 1
    let hasMore = true
    const collected = []

    while (hasMore) {
      const response = await fetch(
        `/api/matches?tournament=${tournament}&page=${page}&perPage=50`
      )
      if (!response.ok) throw new Error(`Page ${page} fetch failed`)
      const { matches, meta } = await response.json()
      collected.push(...matches)
      hasMore = meta.currentPage < meta.totalPages
      page++
    }

    this.allMatches = collected
    return collected
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchAllMatches.perform 'IPL')}}>
      {{if this.fetchAllMatches.isRunning 'Loading pages...' 'Load All Matches'}}
    </button>
    <p>Total loaded: {{this.allMatches.length}}</p>
  </template>
}
```

The `while` loop increments `page` and checks `hasMore` against the server's pagination meta. Each fetched page is spread into the local `collected` array. The entire accumulated result is assigned to `@tracked allMatches` once all pages are done. If any page request fails, the task throws and stops — preventing partial data from silently loading.

