    // raw might have: { first_name, strike_rate, batting_average, career_runs }
    this.player = deepCamelize(raw)
    return this.player
  })

  <template>
    <button type="button" {{on "click" (fn this.loadPlayer.perform @playerId)}}>
      Load Player
    </button>
    {{#if this.player}}
      <p>{{this.player.firstName}} — Avg: {{this.player.battingAverage}}</p>
    {{/if}}
  </template>
}
```

The `deepCamelize` utility recursively converts all object keys from `snake_case` to `camelCase`, handling nested objects and arrays. Defining it outside the component as a pure function keeps the task body focused on async logic. This pattern is common when consuming REST APIs built with Python/Ruby backends that use snake_case conventions.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

const validateScore = ({ runs, wickets, overs }) => {
  const errors = []
  if (typeof runs !== 'number' || runs < 0) errors.push('Runs must be a non-negative number')
  if (typeof wickets !== 'number' || wickets < 0 || wickets > 10) errors.push('Wickets must be 0–10')
  if (typeof overs !== 'number' || overs < 0 || overs > 50) errors.push('Overs must be 0–50')
  return errors
}

export default class ScoreSubmitComponent extends Component {
  @tracked validationErrors = []

  submitScore = task(async (matchId, scoreData) => {
    const errors = validateScore(scoreData)
    if (errors.length > 0) {
      this.validationErrors = errors
      throw new Error(`Validation failed: ${errors.join(', ')}`)
    }
    this.validationErrors = []
    const response = await fetch(`/api/matches/${matchId}/score`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(scoreData),
    })
    if (!response.ok) throw new Error('Score submission failed')
    return response.json()
  })

  <template>
    {{#each this.validationErrors as |error|}}
      <p class="text-red-500">{{error}}</p>
    {{/each}}
    <button type="button"
      {{on "click" (fn this.submitScore.perform @matchId (hash runs=287 wickets=6 overs=50))}}
    >
      Submit Score
    </button>
  </template>
}
```

Validation runs synchronously before any network call, so invalid data is caught immediately without wasting a round trip. The `validateScore` function returns an array of error messages, which are stored in `@tracked validationErrors` for template rendering. Throwing inside the task transitions it to an error state, ensuring callers of `.perform()` can also observe the failure via `last.error`.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class DeleteMatchComponent extends Component {
  @tracked deleted = false

  deleteMatch = task(async (matchId) => {
    // Wrap confirm in Promise for async/await compatibility
    const confirmed = await new Promise((resolve) => {
      // In production replace window.confirm with a proper modal
      resolve(window.confirm(`Delete match ${matchId}? This cannot be undone.`))
    })

    if (!confirmed) return // User cancelled — task ends cleanly

    const response = await fetch(`/api/matches/${matchId}`, {
      method: 'DELETE',
    })
    if (!response.ok) throw new Error('Delete failed')
    this.deleted = true
  })

  <template>
    {{#unless this.deleted}}
      <button
        type="button"
        class="text-red-600"
        disabled={{this.deleteMatch.isRunning}}
        {{on "click" (fn this.deleteMatch.perform @matchId)}}
      >
        Delete Match
      </button>
    {{/unless}}
    {{#if this.deleted}}
      <p>Match deleted.</p>
    {{/if}}
  </template>
}
```

Wrapping `window.confirm` in a `Promise` lets the task `await` a synchronous browser dialog as if it were async. If the user clicks Cancel, the task returns early without error — it simply ends without making the DELETE request. In production, replace `window.confirm` with a custom modal component by resolving the Promise from its confirm/cancel callbacks.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchVideoComponent extends Component {
  @tracked videoSrc = null

  loadVideo = task(async (matchId) => {
    const response = await fetch(`/api/matches/${matchId}/highlights.mp4`)
    if (!response.ok) throw new Error('Video load failed')
    const blob = await response.blob()
    const objectUrl = URL.createObjectURL(blob)
    this.videoSrc = objectUrl

    try {
      // Simulate processing or waiting for user interaction
      await new Promise((resolve) => {
        // Resolve after 5 minutes or when task is cancelled
        setTimeout(resolve, 5 * 60 * 1000)
      })
    } finally {
      // Always revoke the object URL to prevent memory leaks
      URL.revokeObjectURL(objectUrl)
      this.videoSrc = null
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.loadVideo.perform @matchId)}}>
      Load Highlights
    </button>
    {{#if this.videoSrc}}
      <video src={{this.videoSrc}} controls></video>
    {{/if}}
  </template>
}
```

The `finally` block inside a task runs whether the task completes normally, throws, or is cancelled. This makes it the correct place for cleanup code like `URL.revokeObjectURL` — it guarantees no memory leaks regardless of the execution path. If the task is cancelled (e.g., component destroyed), the `finally` block still executes before the task terminates.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class TimedSyncComponent extends Component {
  @tracked score = null
  @tracked elapsedMs = null

  syncScore = task(async (matchId) => {
    const startTime = Date.now()

    try {
      const response = await fetch(`/api/matches/${matchId}/score`)
      if (!response.ok) throw new Error('Sync failed')
      this.score = await response.json()
      return this.score
    } finally {
      this.elapsedMs = Date.now() - startTime
    }
  })

  get elapsedSeconds() {
    if (this.elapsedMs === null) return null
    return (this.elapsedMs / 1000).toFixed(2)
  }

  <template>
    <button type="button" {{on "click" (fn this.syncScore.perform @matchId)}}>
      {{if this.syncScore.isRunning 'Syncing...' 'Sync Score'}}
    </button>
    {{#if this.elapsedSeconds}}
      <p class="text-sm text-gray-500">Last sync: {{this.elapsedSeconds}}s</p>
    {{/if}}
  </template>
}
```

`Date.now()` captures the start timestamp before the async work begins. Computing the difference in `finally` ensures timing is recorded even when the fetch throws. The `get elapsedSeconds` getter converts milliseconds to a human-readable string, and the getter is automatically reactive because it derives from `@tracked elapsedMs`.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class AnalyticsScoreComponent extends Component {
  @tracked score = null

  fetchAndMeasure = task(async (matchId) => {
    const start = performance.now()
    let latencyMs = null

    try {
      const response = await fetch(`/api/matches/${matchId}/score`)
      latencyMs = Math.round(performance.now() - start)
      if (!response.ok) throw new Error(`HTTP ${response.status}`)
      this.score = await response.json()
      return this.score
    } finally {
      if (latencyMs !== null) {
        // Fire-and-forget analytics beacon — don't await
        fetch('/api/analytics/latency', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            endpoint: `/api/matches/${matchId}/score`,
            latencyMs,
            timestamp: new Date().toISOString(),
          }),
        }).catch(() => {}) // Silently ignore analytics errors
      }
    }
  })

  <template>
    <button type="button" {{on "click" (fn this.fetchAndMeasure.perform @matchId)}}>
      Fetch Score
    </button>
  </template>
}
```

`performance.now()` gives sub-millisecond precision compared to `Date.now()`. The analytics beacon is fired as a fire-and-forget POST inside `finally` — it is not awaited so it doesn't block the task's completion. The `.catch(() => {})` silently swallows analytics errors to prevent them from propagating into the main task flow.

