import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class ConditionalProcessorComponent extends Component {
  @tracked report = null

  generateReport = task(async (matchId, options = {}) => {
    const { includeStats = true, includePlayers = true, includeVenue = false } = options
    const report = { matchId }

    // Always fetch base match data
    const matchRes = await fetch(`/api/matches/${matchId}`)
    if (!matchRes.ok) throw new Error('Match fetch failed')
    Object.assign(report, await matchRes.json())

    // Conditionally fetch stats
    if (includeStats) {
      const statsRes = await fetch(`/api/matches/${matchId}/stats`)
      if (statsRes.ok) report.stats = await statsRes.json()
    }

    // Conditionally fetch player details
    if (includePlayers) {
      const playersRes = await fetch(`/api/matches/${matchId}/players`)
      if (playersRes.ok) report.players = await playersRes.json()
    }

    // Conditionally fetch venue info
    if (includeVenue) {
      const venueRes = await fetch(`/api/matches/${matchId}/venue`)
      if (venueRes.ok) report.venue = await venueRes.json()
    }

    this.report = report
    return report
  })

  <template>
    <button type="button"
      {{on "click" (fn this.generateReport.perform @matchId (hash includeStats=true includeVenue=true))}}
    >
      Generate Full Report
    </button>
  </template>
}
```

Destructuring `options` with defaults at the top of the task makes the conditional logic self-documenting. The `if` guards around each fetch mean unnecessary network calls are skipped entirely — important for performance when some sections are not needed. The options are passed from the template using Ember's `(hash)` helper.

