    {{/if}}
  </template>
}
```
`task.isRunning`, `task.last.value`, and `task.last.error` are all reactive properties — they update automatically and trigger re-renders without any `@tracked` boilerplate. This eliminates three common sources of bugs: forgetting to reset flags, setting them in wrong order, and not handling error+loading simultaneously.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'

export default class LiveMatchComponent extends Component {
  // ❌ AVOID — recursive setTimeout leaks after component destroy
  // startPolling() {
  //   setTimeout(async () => {
  //     await this.fetchScore()
  //     this.startPolling()  // no way to stop this cleanly
  //   }, 3000)
  // }

  // ✅ CORRECT — looping task cancels cleanly
  pollLiveScore = task(async () => {
    while (true) {
      const res = await fetch('/api/live-score')
      this.score = await res.json()
      await timeout(3000)
    }
  })

  <template>
    <button {{on "click" (perform this.pollLiveScore)}}>Start Live</button>
    <button {{on "click" this.pollLiveScore.cancelAll}}>Stop</button>
  </template>
}
```
A `while(true)` loop inside a task combined with `timeout()` is cancellation-aware. When the component is destroyed or `cancelAll()` is called, the task stops at the next `await` point — no timers leak. Recursive `setTimeout` has no clean cancellation path and continues firing even after component teardown, causing state mutations on destroyed components and memory leaks.

