```gjs
import Component from '@glimmer/component'
import { task, all } from 'ember-concurrency'

export default class MatchSummaryComponent extends Component {
  loadMatchData = task(async (matchId) => {
    // ✅ all() runs fetches in parallel and waits for ALL to complete
    const [scorecard, commentary, players] = await all([
      fetch(`/api/matches/${matchId}/scorecard`).then(r => r.json()),
      fetch(`/api/matches/${matchId}/commentary`).then(r => r.json()),
      fetch(`/api/matches/${matchId}/players`).then(r => r.json()),
    ])

    return { scorecard, commentary, players }
  })

  <template>
