  loadMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    return await res.json()
    // task.last.error is set automatically if throw occurs
  })
}

// ✅ OPTION B — try/catch: needed when you want to handle cancellation or side-effects
// loadMatch = task(async (matchId) => {
//   try {
//     const res = await fetch(`/api/matches/${matchId}`)
//     return await res.json()
//   } catch (e) {
