    {{! Perform immediately when element is inserted }}
    <div {{did-insert (fn (perform this.loadMatch) @matchId)}}>
      {{#if this.loadMatch.last.value}}
        <p>{{this.loadMatch.last.value.title}}</p>
      {{/if}}
