export default class ConcurrencyCompareComponent extends Component {
  // enqueue with maxConcurrency: 1 — runs one at a time, queues ALL extras
  submitScore = task({ enqueue: true, maxConcurrency: 1 }, async (scoreData) => {
    await fetch('/api/scores', { method: 'POST', body: JSON.stringify(scoreData) })
  })

  // drop — runs one at a time, DISCARDS all extras
  // submitScore = task({ drop: true }, async (scoreData) => { ... })

