import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
export default class MatchComponent extends Component {
  // Debounce, polling, concurrency control, cancellation — all covered
  searchAndPoll = task({ restartable: true }, async (query) => {
    await timeout(300)
    while (true) {
      const res = await fetch(`/api/matches?q=${query}`)
      this.results = await res.json()
      await timeout(10000)
    }
