// ✅ RECOMMENDED: SortableJS for interaction, task only for the API persistence
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'
import Sortable from 'sortablejs'

export default class BattingOrderComponent extends Component {
  @tracked lineup = this.args.lineup

  saveBattingOrder = task({ drop: true }, async (newOrder) => {
    await fetch(`/api/match/${this.args.matchId}/lineup`, {
      method: 'PUT',
      body: JSON.stringify({ lineup: newOrder }),
      headers: { 'Content-Type': 'application/json' }
    })
  })

  setupSortable = (el) => {
    Sortable.create(el, {
      animation: 150,
      onEnd: ({ newIndex, oldIndex }) => {
        const reordered = [...this.lineup]
        const [moved] = reordered.splice(oldIndex, 1)
        reordered.splice(newIndex, 0, moved)
        this.lineup = reordered
        this.saveBattingOrder.perform(reordered)
      }
    })
  }

  <template>
    <ul {{did-insert this.setupSortable}}>
      {{#each this.lineup as |batsman|}}
        <li>{{batsman.name}}</li>
      {{/each}}
    </ul>
    {{#if this.saveBattingOrder.isRunning}}<p>Saving order...</p>{{/if}}
  </template>
}
```

Do not reinvent drag-and-drop physics with a task — SortableJS handles all pointer events, animations, touch support, and accessibility out of the box. Use the task exclusively for the async API persistence step that follows a successful reorder. This separation of concerns keeps your component clean: SortableJS owns the interaction layer, the task owns the network layer.

