// ✅ RECOMMENDED: keepLatest task on hover for perceived speed
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class MatchCardComponent extends Component {
  @tracked prefetchedMatch = null

  prefetchMatch = task({ keepLatest: true }, async () => {
    await timeout(150) // avoid fetch on accidental hover
    this.prefetchedMatch = await fetch(`/api/match/${this.args.matchId}`).then(r => r.json())
  })

  handleHover = () => this.prefetchMatch.perform()

  navigateToMatch = () => {
    if (this.prefetchedMatch) {
      this.args.onNavigate(this.prefetchedMatch)
    } else {
      this.args.onNavigate(null, this.args.matchId)
    }
  }

  <template>
    <div {{on "mouseenter" this.handleHover}} {{on "click" this.navigateToMatch}}>
      {{@match.title}}
    </div>
  </template>
}
```

Hover-prefetch with a `keepLatest` task and a small timeout (100–200ms) dramatically improves perceived navigation speed — by the time the user clicks, the data is already cached. The 150ms debounce prevents wasted fetches during rapid mouse movement across a match list. Use click-only loading for mobile-only UIs (no hover events), low-bandwidth contexts, or when match data is heavy and prefetching would strain the server. On desktop sports dashboards where users browse match cards, hover prefetch is worth implementing.

