```gjs
// ✅ CORRECT — AbortController cancels the fetch when task is cancelled
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreLoader extends Component {
  fetchScore = task(async (matchId) => {
    const controller = new AbortController()
    try {
      const res = await fetch(`/api/matches/${matchId}/score`, {
        signal: controller.signal
      })
      const data = await res.json()
      return data
    } finally {
      controller.abort()
    }
  })
}

<template>
  <button {{on "click" (perform this.fetchScore @matchId)}}>Load Score</button>
  {{#if this.fetchScore.isRunning}}<span>Loading...</span>{{/if}}
  {{#if this.fetchScore.last.value}}
    <p>{{this.fetchScore.last.value.runs}}/{{this.fetchScore.last.value.wickets}}</p>
  {{/if}}
</template>
```

Without `AbortController`, when you call `this.fetchScore.cancelAll()`, the task's generator is cancelled but the underlying `fetch` request continues over the network. The `finally` block calls `controller.abort()` to cancel the in-flight HTTP request. For `restartable` tasks this is especially important as each restart would otherwise pile up network requests.

```gjs
// ❌ WRONG — network errors not caught, only HTTP error codes handled
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class MatchLoader extends Component {
  @tracked match = null

  loadMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    this.match = await res.json()
  })
}
```

```gjs
// ✅ CORRECT — wraps fetch in try/catch to handle both network and HTTP errors
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class MatchLoader extends Component {
  @tracked match = null
  @tracked networkError = null

  loadMatch = task(async (matchId) => {
    this.networkError = null
    let res
    try {
      res = await fetch(`/api/matches/${matchId}`)
    } catch (err) {
      // Network failure: DNS, offline, CORS, timeout
      this.networkError = `Network error: ${err.message}`
      return
    }
    if (!res.ok) throw new Error(`Server error: HTTP ${res.status}`)
    this.match = await res.json()
  })
}

<template>
  {{#if this.networkError}}
    <p class="text-red-500">{{this.networkError}}</p>
  {{/if}}
  {{#if this.loadMatch.last.error}}
    <p class="text-red-500">{{this.loadMatch.last.error.message}}</p>
  {{/if}}
</template>
```

`fetch()` throws a `TypeError` on network failure (offline, DNS, CORS) but does NOT throw on HTTP error codes like 404 or 500. You need both a `try/catch` around the `fetch` call itself AND a `res.ok` check. The task's `task.last.error` only catches unhandled throws, so explicitly setting `@tracked networkError` gives you finer UI control.

```gjs
// ❌ WRONG — catches ALL errors including TaskCancelation, breaking cancel
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'

export default class ScoreSync extends Component {
  syncScore = task(async (matchId) => {
    try {
      const res = await fetch(`/api/matches/${matchId}/score`)
      return await res.json()
    } catch (err) {
      console.error('Sync failed', err)
      // ❌ swallows TaskCancelation — task never truly cancels
    }
  })
}
```

```gjs
// ✅ CORRECT — re-throws TaskCancelation so ember-concurrency can handle it
import Component from '@glimmer/component'
import { task, TaskCancelation } from 'ember-concurrency'

export default class ScoreSync extends Component {
  syncScore = task(async (matchId) => {
    try {
      const res = await fetch(`/api/matches/${matchId}/score`)
      return await res.json()
    } catch (err) {
      if (err instanceof TaskCancelation) throw err  // ✅ always re-throw
      console.error('Sync failed', err)
    }
  })
}

<template>
  <button {{on "click" (perform this.syncScore @matchId)}}>Sync</button>
  <button {{on "click" this.syncScore.cancelAll}}>Cancel</button>
</template>
```

`TaskCancelation` is a special error that ember-concurrency throws internally to unwind async generators when a task is cancelled. If you swallow it in a `catch` block, the task generator continues executing and the `.isRunning` state becomes incorrect. Always check `err instanceof TaskCancelation` and re-throw it immediately.

```gjs
