```gjs
// ✅ CORRECT — store TaskInstance to cancel individually
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class MatchLoader extends Component {
  @tracked activeInstances = new Map()

  loadMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    return await res.json()
  })

  @action
  startLoad(matchId) {
    const instance = this.loadMatch.perform(matchId)  // ✅ store instance
    this.activeInstances = new Map([...this.activeInstances, [matchId, instance]])
  }

  @action
  cancelMatch(matchId) {
    this.activeInstances.get(matchId)?.cancel()  // ✅ cancel specific instance
    this.activeInstances.delete(matchId)
  }
}

<template>
  <button {{on "click" (fn this.startLoad "match_1")}}>Load Match 1</button>
  <button {{on "click" (fn this.cancelMatch "match_1")}}>Cancel Match 1</button>
</template>
```

`task.perform()` returns a `TaskInstance` object. Storing it allows you to call `.cancel()` on that specific run without affecting other concurrent instances. `cancelAll()` cancels every instance — only use that when you want to stop everything.

