// ✅ CORRECT — internal catch keeps the loop alive through transient errors
import Component from '@glimmer/component'
import { task, timeout, TaskCancelation } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class OverTracker extends Component {
  @tracked currentOver = null
  @tracked lastError = null

  trackOvers = task(async (matchId) => {
    while (true) {
      try {
        const res = await fetch(`/api/matches/${matchId}/overs`)
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        this.currentOver = await res.json()
        this.lastError = null
      } catch (err) {
        if (err instanceof TaskCancelation) throw err  // ✅ always re-throw cancel
        this.lastError = err.message
      }
      await timeout(3000)  // continue looping regardless
    }
  })
}

<template>
  {{#if this.lastError}}<p class="text-yellow-400">{{this.lastError}} — retrying...</p>{{/if}}
  {{#if this.currentOver}}<p>Over: {{this.currentOver.number}}</p>{{/if}}
</template>
```

In a polling task, network errors should be transient. Wrapping each iteration's fetch in `try/catch` lets the loop survive and retry on the next tick. Always re-throw `TaskCancelation` so external cancellation still works. Surfacing `this.lastError` in the UI lets users know something is wrong without stopping the stream.

