import { tracked } from '@glimmer/tracking'

export default class ScoreNotes extends Component {
  @tracked notes = ''
  @tracked saveStatus = 'saved'

  autoSave = task({ keepLatest: true }, async (notes) => {  // ✅ latest edit wins
    this.saveStatus = 'saving'
    await timeout(800)  // debounce
    await fetch('/api/notes', {
      method: 'PUT',
      body: JSON.stringify({ notes }),
      headers: { 'Content-Type': 'application/json' }
    })
    this.saveStatus = 'saved'
  })
}

