// ✅ CORRECT — use XMLHttpRequest for upload progress events
import Component from '@glimmer/component'
import { task, waitForEvent } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class PhotoUploader extends Component {
  @tracked percent = 0
  @tracked uploadedUrl = null

  uploadPhoto = task(async (file) => {
    this.percent = 0
    const form = new FormData()
    form.append('photo', file)

    await new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest()
      xhr.upload.addEventListener('progress', (e) => {
        if (e.lengthComputable) {
          this.percent = Math.round((e.loaded / e.total) * 100)  // ✅ reactive updates
        }
      })
      xhr.addEventListener('load', () => {
        if (xhr.status >= 200 && xhr.status < 300) resolve(JSON.parse(xhr.responseText))
        else reject(new Error(`Upload failed: HTTP ${xhr.status}`))
      })
      xhr.addEventListener('error', () => reject(new Error('Network error during upload')))
      xhr.open('POST', '/api/player-photos')
      xhr.send(form)
    })
    this.percent = 100
  })
}

<template>
  {{#if this.uploadPhoto.isRunning}}
    <div class="w-full bg-gray-200 rounded h-2">
      <div class="bg-green-500 h-2 rounded" style="width: {{this.percent}}%"></div>
    </div>
    <p>{{this.percent}}%</p>
  {{/if}}
</template>
```

The `fetch()` API has no upload progress events — `body` is sent opaquely. For upload progress, use `XMLHttpRequest.upload.addEventListener('progress', ...)` and update a `@tracked` property inside the listener. Since the XHR callback runs synchronously in the browser's event loop and Glimmer tracking is reactive, setting `this.percent` inside the progress handler triggers template re-renders correctly.

