```gjs
// ✅ CORRECT — AbortController with setTimeout implements a fetch timeout
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

const TIMEOUT_MS = 8000

export default class MatchLoader extends Component {
  @tracked match = null

  loadMatch = task(async (matchId) => {
    const controller = new AbortController()
    const timer = setTimeout(() => controller.abort(), TIMEOUT_MS)
    try {
      const res = await fetch(`/api/matches/${matchId}`, { signal: controller.signal })
      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      this.match = await res.json()
    } catch (err) {
      if (err.name === 'AbortError') throw new Error(`Request timed out after ${TIMEOUT_MS / 1000}s`)
      throw err
    } finally {
      clearTimeout(timer)  // ✅ always clear the timer
    }
  })
}

<template>
  <button {{on "click" (perform this.loadMatch @matchId)}}>Load</button>
  {{#if this.loadMatch.isRunning}}<span>Loading...</span>{{/if}}
  {{#if this.loadMatch.last.error}}
    <p class="text-red-500">{{this.loadMatch.last.error.message}}</p>
  {{/if}}
</template>
```

Fetch requests have no built-in timeout. If a server accepts a TCP connection but never sends a response, your task hangs until the browser's default limit (often minutes). Using `AbortController` with `setTimeout` gives you control: call `controller.abort()` after N ms and check for `AbortError` to surface a clear timeout message. Always `clearTimeout` in `finally` to prevent the timer firing after a successful early response.

