```gjs
// ✅ CORRECT — exponential backoff with jitter between retries
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

const MAX_RETRIES = 4
const BASE_DELAY_MS = 1000

export default class ScoreRetrier extends Component {
  @tracked score = null
  @tracked attempts = 0

  fetchWithRetry = task(async (matchId) => {
    for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
      try {
        const res = await fetch(`/api/matches/${matchId}/score`)
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        this.score = await res.json()
        this.attempts = attempt + 1
        return
      } catch (err) {
        if (attempt === MAX_RETRIES - 1) throw err
        const delay = BASE_DELAY_MS * 2 ** attempt + Math.random() * 500  // ✅ exponential backoff + jitter
        this.attempts = attempt + 1
        await timeout(delay)
      }
    }
  })
}

<template>
  <button {{on "click" (perform this.fetchWithRetry @matchId)}}>Fetch Score</button>
  {{#if this.fetchWithRetry.isRunning}}
    <p>Attempt {{this.attempts}}... retrying with backoff</p>
  {{/if}}
</template>
```

Immediate retries compound server problems — if the server is struggling, 10 instant requests make it worse. Exponential backoff (`1s → 2s → 4s → 8s`) gives the server time to recover. Adding random jitter (`Math.random() * 500`) prevents multiple clients from retrying in lockstep (thundering herd). `timeout()` from ember-concurrency is cancellable, so if the user navigates away, the retry loop stops cleanly.

