```gjs
// ✅ CORRECT — async/await style (ember-concurrency v3+) is fully cancellable
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class ScoreLoader extends Component {
  @tracked score = null

  // ember-concurrency v3+ uses async/await — fully cancellable at each await point
  loadScore = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}/score`)  // ✅ await in async task
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    this.score = await res.json()
  })

  // ✅ restartable + async = cancel at any await point
  liveScore = task({ restartable: true }, async (matchId) => {
    while (true) {
      const res = await fetch(`/api/matches/${matchId}/score`)
      this.score = await res.json()
      const { timeout } = await import('ember-concurrency')
      await timeout(3000)  // ← cancellable here
    }
  })
}

