import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class DelayedLoader extends Component {
  @tracked result = null

  loadAfterDelay = task(async (matchId) => {
    await timeout(3000)
    if (this.isDestroyed || this.isDestroying) return  // ✅ guard before updating

    const res = await fetch(`/api/matches/${matchId}`)
    const data = await res.json()

    if (this.isDestroyed || this.isDestroying) return  // ✅ guard after each yield
    this.result = data
