import Component from '@glimmer/component'
import { task, taskGroup } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class MatchDashboard extends Component {
  @tracked score = null
  @tracked lineup = null

  // ✅ drop: only one group member runs at a time — others are dropped
  loadGroup = taskGroup({ drop: true })

  loadScore = task({ group: this.loadGroup }, async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}/score`)
    this.score = await res.json()
  })

  loadLineup = task({ group: this.loadGroup }, async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}/lineup`)
    this.lineup = await res.json()
  })
}

<template>
  {{#if this.loadGroup.isRunning}}<p>Loading...</p>{{/if}}
  <button {{on "click" (perform this.loadScore @matchId)}}>Load Score</button>
  <button {{on "click" (perform this.loadLineup @matchId)}}>Load Lineup</button>
</template>
```

A `taskGroup` without a concurrency policy (`drop`, `restartable`, `enqueue`, `keepLatest`) does NOT enforce mutual exclusion — member tasks still run concurrently. The group only provides shared `isRunning` / `isIdle` state. To enforce "only one member runs at a time", specify `drop`, `restartable`, or `enqueue` as an option to `taskGroup()`.

```gjs
