  loadData = task(async (matchId) => {
    // ❌ if connectionService.isReady never becomes true, task hangs indefinitely
    await waitForProperty(this.connectionService, 'isReady', true)
    const res = await fetch(`/api/matches/${matchId}`)
    return await res.json()
