```gjs
// ✅ CORRECT — race waitForProperty against a timeout to prevent infinite hang
import Component from '@glimmer/component'
import { task, waitForProperty, timeout, race } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { service } from '@ember/service'

const READY_TIMEOUT_MS = 10000

export default class DataLoader extends Component {
  @service connectionService
  @tracked timedOut = false

  loadData = task(async (matchId) => {
    this.timedOut = false
    const result = await race([
      waitForProperty(this.connectionService, 'isReady', true),
      timeout(READY_TIMEOUT_MS).then(() => 'timeout')
    ])
    if (result === 'timeout') {
      this.timedOut = true
      return null  // ✅ give up gracefully
    }
    const res = await fetch(`/api/matches/${matchId}`)
    return await res.json()
  })
}

<template>
  {{#if this.timedOut}}
    <p class="text-red-400">Connection timed out. Please check your network.</p>
  {{/if}}
  <button {{on "click" (perform this.loadData @matchId)}}>Load</button>
</template>
```

`waitForProperty()` is an indefinite wait — it will wait forever if the property never matches. Always pair it with a `timeout()` via `race()` to implement a deadline. This also ensures the task is cancellable from outside. The pattern `race([waitForProperty(...), timeout(N)])` is the idiomatic guard for waiting on external state in ember-concurrency.

```gjs
