```gjs
// ✅ CORRECT — AbortController cancels waitForEvent when component destroys
import Component from '@glimmer/component'
import { task, waitForEvent, timeout, race } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class ScoreModal extends Component {
  @tracked wasClosed = false

  waitForClose = task(async (modalElement) => {
    // ✅ race against a timeout OR cancel on willDestroy
    await race([
      waitForEvent(modalElement, 'close'),
      waitForEvent(modalElement, 'remove'),
      timeout(30000)  // auto-give-up after 30s
    ])
    this.wasClosed = true
  })

  willDestroy() {
    super.willDestroy()
    this.waitForClose.cancelAll()  // ✅ cancel if component unmounts
  }
}

<template>
  {{#if this.wasClosed}}<p>Modal was dismissed.</p>{{/if}}
</template>
```

`waitForEvent()` holds a `addEventListener` on the element. If that element is removed from the DOM, the event never fires and the event listener is never cleaned up — causing a memory leak and a hanging task. Guard by: (1) cancelling the task in `willDestroy`, (2) racing against a `timeout`, or (3) racing against a `remove`/`animationend` event. Cancelling in `willDestroy` is the safest fallback.

