// ✅ CORRECT — cancel task on deactivate, return model properly
import Route from '@ember/routing/route'
import { task } from 'ember-concurrency'

export default class MatchRoute extends Route {
  loadMatch = task(async (matchId) => {
    const res = await fetch(`/api/matches/${matchId}`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    return await res.json()
  })

  async model(params) {
    // ✅ await the task instance — route waits for data before rendering
    return await this.loadMatch.perform(params.match_id)
  }

  deactivate() {
    super.deactivate()
    this.loadMatch.cancelAll()  // ✅ cancel on route exit
  }
}
