// ✅ CORRECT — catch save rejection, surface record.errors in template
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class PlayerForm extends Component {
  @tracked validationErrors = []

  savePlayer = task({ drop: true }, async (player) => {
    this.validationErrors = []
    try {
      await player.save()
    } catch (err) {
      // Ember Data surfaces server 422 errors as record.errors
      if (player.errors.length > 0) {
        this.validationErrors = player.errors.map(e => `${e.attribute}: ${e.message}`)
      } else {
        throw err  // re-throw non-validation errors
      }
    }
  })
}

<template>
  {{#each this.validationErrors as |error|}}
    <p class="text-red-500">{{error}}</p>
  {{/each}}
  <button {{on "click" (perform this.savePlayer @player)}}>Save Player</button>
</template>
