  calculateNRR = task(async (runsFor, runsAgainst, overs) => {
    const [result] = await Promise.all([
      // actual computation or fast API call
      Promise.resolve((runsFor / overs) - (runsAgainst / overs)),
      timeout(MIN_LOADING_MS)  // ✅ ensures spinner shows for at least 300ms
    ])
    this.nrr = result
  })
