    this.isLiked = !this.isLiked  // optimistic
    this.likeCount += this.isLiked ? 1 : -1
    try {
      await fetch(`/api/matches/${matchId}/like`, { method: 'POST' })
    } catch (err) {
      // ❌ rollback on error but NOT on cancel
      this.isLiked = prev.isLiked
      this.likeCount = prev.count
      throw err
    }
