```gjs
// ✅ CORRECT — rollback in finally or check TaskCancelation to rollback on cancel too
import Component from '@glimmer/component'
import { task, TaskCancelation } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class LikeButton extends Component {
  @tracked isLiked = false
  @tracked likeCount = 0

  toggleLike = task({ drop: true }, async (matchId) => {
    const prev = { isLiked: this.isLiked, count: this.likeCount }
    this.isLiked = !this.isLiked
    this.likeCount += this.isLiked ? 1 : -1
    try {
      await fetch(`/api/matches/${matchId}/like`, { method: 'POST' })
    } catch (err) {
      if (err instanceof TaskCancelation) {
        // ✅ also rollback when task is cancelled
        this.isLiked = prev.isLiked
        this.likeCount = prev.count
        throw err
      }
      this.isLiked = prev.isLiked
      this.likeCount = prev.count
      throw err
    }
  })
}

<template>
  <button {{on "click" (perform this.toggleLike @matchId)}}>
