    if (!res.ok) throw new Error('Lineup fetch failed')
    return await res.json()
  })

  loadAll = task(async (matchId) => {
    // ✅ if either task fails, the other is cancelled
    const [score, lineup] = await all([
      this.fetchScore.perform(matchId),
      this.fetchLineup.perform(matchId)
    ])
    this.matchData = { score, lineup }
  })
