import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const DEBOUNCE_MS = 300

export default class PlayerSearch extends Component {
  @tracked query = ''
  @tracked results = []

  search = task({ restartable: true }, async (query) => {
    await timeout(DEBOUNCE_MS)  // ✅ restartable cancels previous at this yield
    if (!query.trim()) { this.results = []; return }
    const res = await fetch(`/api/players?q=${encodeURIComponent(query)}`)
    this.results = await res.json()
  })

  @action
  onInput(event) {
    this.query = event.target.value
    this.search.perform(this.query)
  }
}

