  uploadScore = task({ enqueue: true, maxConcurrency: 2 }, async (scoreData) => {
    this.queueSize = this.uploadScore.numQueued
    await fetch('/api/scores', {
      method: 'POST',
      body: JSON.stringify(scoreData),
      headers: { 'Content-Type': 'application/json' }
