// ✅ CORRECT — check for cancellation before side-effectful work in finally
import Component from '@glimmer/component'
import { task, TaskCancelation } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class MatchRecorder extends Component {
  @tracked recording = false

  recordMatch = task(async (matchId) => {
    this.recording = true
    let wasCancelled = false
    try {
      await fetch(`/api/matches/${matchId}/record`, { method: 'POST' })
    } catch (err) {
      if (err instanceof TaskCancelation) wasCancelled = true
      else throw err
    } finally {
      this.recording = false
      if (!wasCancelled) {
        this.saveLog.perform(matchId)  // ✅ only log on normal completion
      }
    }
  })

  saveLog = task(async (matchId) => {
    await fetch(`/api/matches/${matchId}/log`, { method: 'POST' })
  })
}

