    // ✅ DEV assertion: warn if property doesn't exist (catches typos in dev)
    if (import.meta.env?.DEV && !('isConnected' in this.networkService)) {
      console.warn('waitForProperty: isConnected not found on networkService')
    }

    const result = await race([
      waitForProperty(this.networkService, 'isConnected', true),  // ✅ correct spelling
      timeout(10000).then(() => 'timeout')
    ])

    if (result === 'timeout') {
      this.syncError = 'Network connection timed out'
      return null
    }

    const res = await fetch(`/api/matches/${matchId}/sync`)
    return await res.json()
