import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class LiveScoreTicker extends Component {
  @tracked score = null
  @tracked lastUpdated = null
  POLL_INTERVAL = 5000

  pollScore = task({ restartable: true }, async (matchId) => {
    while (true) {
      try {
        const res = await fetch(`/api/matches/${matchId}/score`)
        if (!res.ok) throw new Error(`HTTP ${res.status}`)
        if (!this.isDestroyed && !this.isDestroying) {
          this.score = await res.json()
          this.lastUpdated = new Date().toLocaleTimeString()
        }
      } catch (err) {
        // log but continue polling
        console.warn('Score poll error:', err.message)
      }
      await timeout(this.POLL_INTERVAL)
    }
  })

  @action
  startPolling() { this.pollScore.perform(this.args.matchId) }

  @action
  stopPolling() { this.pollScore.cancelAll() }

  willDestroy() {
    super.willDestroy()
    this.pollScore.cancelAll()
  }
}

<template>
  <div class="bg-green-900 text-white rounded-xl p-6 shadow-lg max-w-sm">
    <div class="flex justify-between items-center mb-4">
      <h2 class="text-lg font-bold">Live Score</h2>
      <span class="text-xs text-green-300">
        {{#if this.pollScore.isRunning}}🟢 Live{{else}}⚫ Paused{{/if}}
      </span>
    </div>
    {{#if this.score}}
      <p class="text-4xl font-mono font-bold">{{this.score.runs}}/{{this.score.wickets}}</p>
      <p class="text-sm text-green-300 mt-1">{{this.score.overs}} overs</p>
      <p class="text-xs text-green-400 mt-2">Updated: {{this.lastUpdated}}</p>
    {{else}}
      <p class="text-green-400 animate-pulse">Waiting for data...</p>
    {{/if}}
    <div class="flex gap-2 mt-4">
      <button
        {{on "click" this.startPolling}}
        disabled={{this.pollScore.isRunning}}
        class="flex-1 bg-green-600 hover:bg-green-500 disabled:opacity-40 rounded px-3 py-2 text-sm"
      >Start</button>
      <button
        {{on "click" this.stopPolling}}
        disabled={{this.pollScore.isIdle}}
        class="flex-1 bg-red-600 hover:bg-red-500 disabled:opacity-40 rounded px-3 py-2 text-sm"
      >Stop</button>
    </div>
  </div>
</template>
```

This component demonstrates the `restartable` polling loop pattern. `while(true)` with `await timeout(POLL_INTERVAL)` creates a self-scheduling ticker. The `restartable` policy ensures only one loop runs regardless of how many times `startPolling` is called. Errors are caught internally to keep the loop alive through transient network failures, and `willDestroy` cancels the task during component teardown.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const DEBOUNCE_MS = 350
const MIN_QUERY_LENGTH = 2

export default class PlayerSearch extends Component {
  @tracked query = ''
  @tracked results = []
  @tracked selectedPlayer = null

  search = task({ restartable: true }, async (query) => {
    if (query.length < MIN_QUERY_LENGTH) {
      this.results = []
      return
    }
    await timeout(DEBOUNCE_MS)  // cancellable debounce
    const res = await fetch(`/api/players?q=${encodeURIComponent(query)}&limit=8`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    this.results = await res.json()
  })

  @action
  onInput(event) {
    this.query = event.target.value
    this.search.perform(this.query)
  }

  @action
  selectPlayer(player) {
    this.selectedPlayer = player
    this.query = player.name
    this.results = []
  }

  @action
  clearSearch() {
    this.query = ''
    this.results = []
    this.selectedPlayer = null
    this.search.cancelAll()
  }
}

<template>
  <div class="relative w-full max-w-md">
    <div class="relative">
      <input
        value={{this.query}}
        {{on "input" this.onInput}}
        placeholder="Search players..."
        class="w-full border border-gray-300 rounded-lg px-4 py-2 pr-10 focus:outline-none focus:ring-2 focus:ring-green-500"
      />
      {{#if this.search.isRunning}}
        <span class="absolute right-3 top-2.5 animate-spin text-gray-400">⟳</span>
      {{else if this.query}}
        <button {{on "click" this.clearSearch}} class="absolute right-3 top-2.5 text-gray-400 hover:text-gray-600">✕</button>
      {{/if}}
    </div>
    {{#if this.search.last.error}}
      <p class="text-red-500 text-sm mt-1">{{this.search.last.error.message}}</p>
    {{/if}}
    {{#if this.results.length}}
      <ul class="absolute z-10 w-full bg-white border border-gray-200 rounded-lg shadow-lg mt-1 max-h-64 overflow-y-auto">
        {{#each this.results as |player|}}
          <li>
            <button
              {{on "click" (fn this.selectPlayer player)}}
              class="w-full text-left px-4 py-2 hover:bg-green-50 flex items-center gap-3"
            >
              <span class="font-medium">{{player.name}}</span>
              <span class="text-sm text-gray-500">{{player.team}}</span>
            </button>
          </li>
        {{/each}}
      </ul>
    {{/if}}
    {{#if this.selectedPlayer}}
      <div class="mt-3 p-3 bg-green-50 rounded-lg border border-green-200">
        <p class="font-semibold text-green-800">{{this.selectedPlayer.name}}</p>
        <p class="text-sm text-green-600">{{this.selectedPlayer.team}} · {{this.selectedPlayer.role}}</p>
      </div>
    {{/if}}
  </div>
</template>
```

The `restartable` + `timeout(DEBOUNCE_MS)` combination is ember-concurrency's idiomatic debounce: each new keystroke cancels the previous task at the `await timeout()` yield point, so the API is only called after the user pauses typing for 350ms. The `MIN_QUERY_LENGTH` guard prevents API calls on very short queries. Results are cleared immediately on selection to close the dropdown.

