import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class ScoreSubmissionForm extends Component {
  @tracked runs = ''
  @tracked wickets = ''
  @tracked overs = ''
  @tracked extras = '0'
  @tracked submitted = false
  @tracked submitError = null

  get isValid() {
    const r = Number(this.runs)
    const w = Number(this.wickets)
    const o = Number(this.overs)
    return (
      this.runs !== '' && !isNaN(r) && r >= 0 &&
      this.wickets !== '' && !isNaN(w) && w >= 0 && w <= 10 &&
      this.overs !== '' && !isNaN(o) && o > 0 && o <= 50
    )
  }

  get canSubmit() {
    return this.isValid && !this.submitScore.isRunning
  }

  submitScore = task({ drop: true }, async () => {
    if (!this.isValid) return
    this.submitError = null
    const payload = {
      runs: Number(this.runs),
      wickets: Number(this.wickets),
      overs: Number(this.overs),
      extras: Number(this.extras)
    }
    const res = await fetch(`/api/matches/${this.args.matchId}/score`, {
      method: 'POST',
      body: JSON.stringify(payload),
      headers: { 'Content-Type': 'application/json' }
    })
    if (!res.ok) {
      const body = await res.json().catch(() => ({}))
      throw new Error(body.message ?? `HTTP ${res.status}`)
    }
    this.submitted = true
  })

  @action reset() {
    this.runs = ''
    this.wickets = ''
    this.overs = ''
    this.extras = '0'
    this.submitted = false
    this.submitError = null
  }
}

