import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class TournamentStandings extends Component {
  @tracked standings = []
  @tracked sortKey = 'points'
  @tracked sortDir = 'desc'

  loadStandings = task({ drop: true }, async (tournamentId) => {
    const res = await fetch(`/api/tournaments/${tournamentId}/standings`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    this.standings = await res.json()
  })

  get sortedStandings() {
    return [...this.standings].sort((a, b) => {
      const dir = this.sortDir === 'asc' ? 1 : -1
      if (typeof a[this.sortKey] === 'string') {
        return a[this.sortKey].localeCompare(b[this.sortKey]) * dir
      }
      return (a[this.sortKey] - b[this.sortKey]) * dir
    })
  }

  @action
  sortBy(key) {
    if (this.sortKey === key) {
      this.sortDir = this.sortDir === 'asc' ? 'desc' : 'asc'
    } else {
      this.sortKey = key
      this.sortDir = 'desc'
    }
  }

  @action
  refresh() { this.loadStandings.perform(this.args.tournamentId) }
}

<template>
