            {{#each (array "played" "won" "lost" "points" "nrr") as |col|}}
              <th
                class="text-right py-2 pr-2 cursor-pointer hover:text-green-600 select-none"
                {{on "click" (fn this.sortBy col)}}
              >
                {{col}}
                {{#if (eq this.sortKey col)}}{{if (eq this.sortDir "asc") "↑" "↓"}}{{/if}}
