import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const POLL_INTERVAL = 8000
const MAX_COMMENTS = 50

export default class CommentaryFeed extends Component {
  @tracked comments = []
  @tracked lastCommentId = null

  pollCommentary = task({ restartable: true }, async (matchId) => {
    while (true) {
      const url = this.lastCommentId
        ? `/api/matches/${matchId}/commentary?after=${this.lastCommentId}`
        : `/api/matches/${matchId}/commentary?limit=10`
      const res = await fetch(url)
      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const newComments = await res.json()
      if (newComments.length > 0) {
        // Prepend new items, cap at MAX_COMMENTS
        this.comments = [...newComments, ...this.comments].slice(0, MAX_COMMENTS)
        this.lastCommentId = newComments[0].id
      }
      await timeout(POLL_INTERVAL)
    }
  })

  @action start() { this.pollCommentary.perform(this.args.matchId) }
  @action stop() { this.pollCommentary.cancelAll() }

  @action clearFeed() {
    this.comments = []
    this.lastCommentId = null
  }

  willDestroy() {
    super.willDestroy()
    this.pollCommentary.cancelAll()
  }
}

<template>
  <div class="bg-gray-900 text-white rounded-2xl shadow-lg flex flex-col h-[500px]">
    <div class="flex justify-between items-center px-4 py-3 border-b border-gray-700">
      <h2 class="font-bold">Live Commentary</h2>
      <div class="flex gap-2">
        {{#if this.pollCommentary.isRunning}}
          <span class="text-xs text-green-400 animate-pulse">● LIVE</span>
          <button {{on "click" this.stop}} class="text-xs text-gray-400 hover:text-white bg-gray-700 px-2 py-1 rounded">Stop</button>
        {{else}}
          <button {{on "click" this.start}} class="text-xs text-green-400 bg-gray-700 px-2 py-1 rounded hover:bg-gray-600">Start</button>
        {{/if}}
        <button {{on "click" this.clearFeed}} class="text-xs text-gray-500 hover:text-white">Clear</button>
      </div>
    </div>
    {{#if this.pollCommentary.last.error}}
      <p class="text-red-400 text-sm p-3">{{this.pollCommentary.last.error.message}}</p>
    {{/if}}
    <div class="flex-1 overflow-y-auto p-4 space-y-3">
      {{#each this.comments as |comment|}}
        <div class="border-l-2 border-green-500 pl-3">
          <div class="flex items-center gap-2 mb-1">
            <span class="text-xs font-bold text-green-400">{{comment.over}}</span>
            {{#if comment.isWicket}}<span class="bg-red-500 text-white text-xs px-1.5 rounded">WICKET</span>{{/if}}
            {{#if comment.isBoundary}}<span class="bg-yellow-500 text-black text-xs px-1.5 rounded">{{comment.runs}}</span>{{/if}}
          </div>
          <p class="text-sm text-gray-300">{{comment.text}}</p>
        </div>
      {{else}}
        <p class="text-gray-500 text-center">No commentary yet. Start the feed.</p>
      {{/each}}
    </div>
  </div>
</template>
```

New comments are prepended (newest first) using spread: `[...newComments, ...this.comments]`. The `?after=lastId` cursor prevents re-fetching old comments on each poll. `MAX_COMMENTS` caps the array to prevent unbounded memory growth. The feed distinguishes wickets and boundaries with colored badges. The task is cancelable at the `await timeout()` yield point for clean shutdown.

