import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const PAGE_SIZE = 10

export default class MatchSchedule extends Component {
  @tracked fixtures = []
  @tracked page = 0
  @tracked hasMore = true
  @tracked totalCount = 0

  loadPage = task({ enqueue: true }, async () => {
    const offset = this.page * PAGE_SIZE
    const res = await fetch(
      `/api/fixtures?offset=${offset}&limit=${PAGE_SIZE}&tournamentId=${this.args.tournamentId}`
    )
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    const data = await res.json()
    this.fixtures = [...this.fixtures, ...data.items]
    this.totalCount = data.total
    this.hasMore = this.fixtures.length < data.total
    this.page++
  })

  get loadPercent() {
    if (!this.totalCount) return 0
    return Math.round((this.fixtures.length / this.totalCount) * 100)
  }
}

<template>
  <div class="max-w-lg mx-auto">
    <div class="flex justify-between items-center mb-4">
      <h2 class="font-bold text-gray-800">Match Schedule</h2>
      <span class="text-xs text-gray-400">{{this.fixtures.length}} / {{this.totalCount}}</span>
    </div>
    {{#if this.loadPage.last.error}}
      <p class="text-red-500 text-sm mb-3">{{this.loadPage.last.error.message}}</p>
    {{/if}}
    <div class="space-y-2">
      {{#each this.fixtures as |fixture|}}
        <div class="bg-white border border-gray-100 rounded-xl px-4 py-3 shadow-sm">
          <div class="flex justify-between">
            <span class="font-medium text-sm">{{fixture.homeTeam}} vs {{fixture.awayTeam}}</span>
            <span class="text-xs text-gray-400">{{fixture.format}}</span>
          </div>
          <p class="text-xs text-gray-400 mt-1">{{fixture.date}} · {{fixture.venue}}</p>
        </div>
      {{/each}}
    </div>
    {{#if this.hasMore}}
      <button
        {{on "click" (perform this.loadPage)}}
        disabled={{this.loadPage.isRunning}}
        class="mt-4 w-full border border-green-300 text-green-600 rounded-xl py-3 text-sm font-medium hover:bg-green-50 disabled:opacity-40"
      >
        {{#if this.loadPage.isRunning}}
          <span class="animate-pulse">Loading...</span>
        {{else}}
          Load More ({{subtract this.totalCount this.fixtures.length}} remaining)
        {{/if}}
      </button>
    {{else if this.fixtures.length}}
      <p class="mt-4 text-center text-xs text-gray-400">All {{this.totalCount}} fixtures loaded</p>
    {{/if}}
    {{#if this.fixtures.length}}
      <div class="mt-3 h-1 bg-gray-100 rounded-full">
        <div class="h-1 bg-green-400 rounded-full transition-all" style="width: {{this.loadPercent}}%"></div>
      </div>
    {{/if}}
  </div>
</template>
