import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class PlayerPhotoUploader extends Component {
  @tracked percent = 0
  @tracked previewUrl = null
  @tracked uploadedUrl = null
  @tracked selectedFile = null

  uploadPhoto = task({ drop: true }, async (file, playerId) => {
    this.percent = 0
    this.uploadedUrl = null
    const form = new FormData()
    form.append('photo', file)
    form.append('playerId', playerId)

    const result = await new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest()
      xhr.upload.addEventListener('progress', (e) => {
        if (e.lengthComputable) this.percent = Math.round((e.loaded / e.total) * 100)
      })
      xhr.addEventListener('load', () => {
        if (xhr.status >= 200 && xhr.status < 300) resolve(JSON.parse(xhr.responseText))
        else reject(new Error(`Upload failed (HTTP ${xhr.status})`))
      })
      xhr.addEventListener('error', () => reject(new Error('Network error')))
      xhr.open('POST', '/api/players/photos')
      xhr.send(form)
    })
    this.uploadedUrl = result.url
  })

  @action
  onFileSelect(event) {
    const file = event.target.files[0]
    if (!file) return
    if (!file.type.startsWith('image/')) { alert('Please select an image file'); return }
    if (file.size > 5 * 1024 * 1024) { alert('File too large (max 5MB)'); return }
    this.selectedFile = file
    this.previewUrl = URL.createObjectURL(file)
    this.uploadedUrl = null
  }

  @action
  startUpload() {
    if (this.selectedFile) {
      this.uploadPhoto.perform(this.selectedFile, this.args.playerId)
