        </div>
      {{/if}}
    </div>
    <input type="file" accept="image/*" {{on "change" this.onFileSelect}} class="hidden" id="photo-input" />
    <label for="photo-input" class="block w-full text-center border-2 border-dashed border-gray-300 rounded-lg py-3 text-sm text-gray-500 cursor-pointer hover:border-green-400 hover:text-green-600">
      {{if this.selectedFile this.selectedFile.name "Choose Photo"}}
    </label>
    {{#if this.uploadPhoto.isRunning}}
      <div class="mt-4">
        <div class="flex justify-between text-xs text-gray-500 mb-1">
          <span>Uploading...</span><span>{{this.percent}}%</span>
        </div>
        <div class="w-full bg-gray-100 rounded-full h-2">
          <div class="bg-green-500 h-2 rounded-full transition-all duration-150" style="width: {{this.percent}}%"></div>
        </div>
      </div>
    {{else if this.uploadedUrl}}
      <p class="mt-4 text-center text-green-600 font-medium text-sm">✓ Photo uploaded successfully</p>
