```

XHR is required for upload progress — `fetch()` has no upload progress API. The `percent` property is updated in real-time inside the `progress` event listener, and Glimmer's tracking system re-renders the progress bar on each update. `URL.createObjectURL` creates a local preview instantly without an upload. `willDestroy` revokes the object URL to free memory.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const FORMATS = [
  { id: 'pdf', label: 'PDF', icon: '📄' },
  { id: 'csv', label: 'CSV', icon: '📊' },
  { id: 'json', label: 'JSON', icon: '{ }' }
]

export default class ScorecardExporter extends Component {
  @tracked selectedFormat = 'pdf'
  @tracked downloadUrl = null
  formats = FORMATS

  exportScorecard = task({ drop: true }, async (matchId, format) => {
    this.downloadUrl = null
    const res = await fetch(`/api/matches/${matchId}/scorecard/export?format=${format}`, {
      headers: { Accept: 'application/octet-stream' }
    })
    if (!res.ok) throw new Error(`Export failed (HTTP ${res.status})`)
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = `scorecard-${matchId}.${format}`
    link.click()
    URL.revokeObjectURL(url)
    this.downloadUrl = url  // signal success
  })

  @action setFormat(format) { this.selectedFormat = format }

  @action doExport() {
    this.exportScorecard.perform(this.args.matchId, this.selectedFormat)
  }
}

