import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const DEBOUNCE_MS = 400

export default class MatchSearch extends Component {
  @tracked query = ''
  @tracked format = ''
  @tracked team = ''
  @tracked dateFrom = ''
  @tracked dateTo = ''
  @tracked results = []
  @tracked resultCount = 0

  search = task({ restartable: true }, async () => {
    await timeout(DEBOUNCE_MS)
    const params = new URLSearchParams()
    if (this.query) params.set('q', this.query)
    if (this.format) params.set('format', this.format)
    if (this.team) params.set('team', this.team)
    if (this.dateFrom) params.set('from', this.dateFrom)
    if (this.dateTo) params.set('to', this.dateTo)
    const res = await fetch(`/api/matches/search?${params}`)
    if (!res.ok) throw new Error(`HTTP ${res.status}`)
    const data = await res.json()
    this.results = data.items
    this.resultCount = data.total
  })

  @action onQueryChange(e) { this.query = e.target.value; this.search.perform() }
  @action onFormatChange(e) { this.format = e.target.value; this.search.perform() }
  @action onTeamChange(e) { this.team = e.target.value; this.search.perform() }
  @action onDateFromChange(e) { this.dateFrom = e.target.value; this.search.perform() }
  @action onDateToChange(e) { this.dateTo = e.target.value; this.search.perform() }

  @action clearFilters() {
    this.query = ''
    this.format = ''
    this.team = ''
    this.dateFrom = ''
    this.dateTo = ''
    this.results = []
    this.resultCount = 0
    this.search.cancelAll()
  }

  get hasFilters() { return !!(this.query || this.format || this.team || this.dateFrom || this.dateTo) }
}

<template>
  <div class="bg-white rounded-2xl shadow p-5 space-y-4">
    <div class="flex justify-between items-center">
      <h2 class="font-bold text-gray-800">Search Matches</h2>
      {{#if this.hasFilters}}
        <button {{on "click" this.clearFilters}} class="text-xs text-gray-400 hover:text-red-500">Clear filters</button>
      {{/if}}
    </div>
    <input value={{this.query}} {{on "input" this.onQueryChange}}
      placeholder="Search by team, player, venue..."
      class="w-full border rounded-lg px-4 py-2 text-sm focus:ring-2 focus:ring-green-400" />
    <div class="grid grid-cols-3 gap-3">
      <select {{on "change" this.onFormatChange}} class="border rounded-lg px-3 py-2 text-sm">
        <option value="">All Formats</option>
        <option value="test">Test</option>
        <option value="odi">ODI</option>
        <option value="t20">T20</option>
      </select>
      <input type="date" value={{this.dateFrom}} {{on "change" this.onDateFromChange}}
        class="border rounded-lg px-3 py-2 text-sm" />
      <input type="date" value={{this.dateTo}} {{on "change" this.onDateToChange}}
        class="border rounded-lg px-3 py-2 text-sm" />
    </div>
    {{#if this.search.isRunning}}
      <div class="space-y-2">
        {{#each (array 1 2 3) as |_|}}<div class="animate-pulse h-12 bg-gray-100 rounded"></div>{{/each}}
      </div>
    {{else if this.search.last.error}}
      <p class="text-red-500 text-sm">{{this.search.last.error.message}}</p>
    {{else if this.results.length}}
      <p class="text-xs text-gray-400">{{this.resultCount}} results</p>
      <div class="space-y-2">
        {{#each this.results as |match|}}
          <div class="border border-gray-100 rounded-xl p-3">
            <p class="font-medium text-sm">{{match.homeTeam}} vs {{match.awayTeam}}</p>
            <p class="text-xs text-gray-400">{{match.format}} · {{match.date}} · {{match.venue}}</p>
          </div>
        {{/each}}
      </div>
    {{else if this.hasFilters}}
      <p class="text-center text-gray-400 text-sm py-4">No matches found for these filters.</p>
    {{/if}}
  </div>
</template>
```

Every filter change calls `this.search.perform()`. The `restartable` + `await timeout(DEBOUNCE_MS)` at the start means rapid filter changes cancel the previous search and only the last filter state fires the API. `URLSearchParams` cleanly builds the query string, omitting empty values. The `hasFilters` getter controls whether to show the "Clear filters" link and the empty state message.

