import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class FanPoll extends Component {
  @tracked selectedOption = null
  @tracked hasVoted = false
  @tracked results = null

  submitVote = task({ drop: true }, async (pollId, option) => {
    const res = await fetch(`/api/polls/${pollId}/vote`, {
      method: 'POST',
      body: JSON.stringify({ option }),
      headers: { 'Content-Type': 'application/json' }
    })
    if (!res.ok) throw new Error(`Vote failed (HTTP ${res.status})`)
    this.results = await res.json()
    this.hasVoted = true
  })

  @action selectOption(option) {
    if (!this.hasVoted) this.selectedOption = option
  }

  get totalVotes() {
    if (!this.results) return 0
    return this.results.options.reduce((sum, o) => sum + o.votes, 0)
  }

  percentFor(option) {
    if (!this.results || !this.totalVotes) return 0
    const opt = this.results.options.find(o => o.id === option.id)
    return Math.round(((opt?.votes ?? 0) / this.totalVotes) * 100)
  }
}

<template>
  <div class="bg-white rounded-2xl shadow-md p-5 max-w-sm">
    <h3 class="font-bold text-gray-800 mb-1">{{@poll.question}}</h3>
