            <div class="relative flex justify-between items-center">
              <span class="font-medium text-sm">{{option.label}}</span>
              {{#if this.hasVoted}}
                <span class="font-bold text-green-700 text-sm">{{this.percentFor option}}%</span>
              {{/if}}
            </div>
          </div>
        </button>
      {{/each}}
    </div>
    {{#unless this.hasVoted}}
      <button
        {{on "click" (perform this.submitVote @poll.id this.selectedOption.id)}}
        disabled={{or (not this.selectedOption) this.submitVote.isRunning}}
        class="mt-4 w-full bg-green-600 text-white rounded-xl py-2.5 text-sm font-medium disabled:opacity-40 hover:bg-green-500"
