After voting, each option button shows an inline progress bar using an absolutely-positioned `div` with a percentage width, creating a clean vote visualization. The `drop` policy prevents double-votes from double-clicks. Options are disabled after voting (`cursor-default`) and the submit button disappears. The `percentFor` helper method computes each option's share from the server-returned results.

```gjs
import Component from '@glimmer/component'
import { task, timeout } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const ANSWER_DISPLAY_MS = 2000
const QUESTION_TIME_MS = 15000

export default class CricketQuiz extends Component {
  @tracked questions = []
  @tracked currentIndex = 0
  @tracked selectedAnswer = null
  @tracked score = 0
  @tracked quizDone = false
  @tracked timeLeft = QUESTION_TIME_MS / 1000

  loadQuiz = task({ drop: true }, async (tournamentId) => {
    const res = await fetch(`/api/quizzes?tournament=${tournamentId}&limit=10`)
    if (!res.ok) throw new Error('Could not load quiz')
    this.questions = await res.json()
    if (this.questions.length > 0) this.runQuestion.perform()
  })

  runQuestion = task({ restartable: true }, async () => {
    this.selectedAnswer = null
    this.timeLeft = QUESTION_TIME_MS / 1000
    // Count down 1 second at a time
    for (let t = QUESTION_TIME_MS / 1000; t > 0; t--) {
      await timeout(1000)
      this.timeLeft = t - 1
    }
    // Auto-advance on timeout (no answer selected)
    this.advance(null)
  })

  @action
  answer(choice) {
    if (this.selectedAnswer) return
    this.selectedAnswer = choice
    this.runQuestion.cancelAll()
    const q = this.questions[this.currentIndex]
    if (choice === q.correctAnswer) this.score++
    setTimeout(() => this.advance(choice), ANSWER_DISPLAY_MS)
  }

  @action
  advance(_choice) {
    if (this.currentIndex >= this.questions.length - 1) {
      this.quizDone = true
    } else {
      this.currentIndex++
      this.runQuestion.perform()
    }
  }

  get currentQuestion() { return this.questions[this.currentIndex] }
  get progressPercent() { return Math.round((this.currentIndex / this.questions.length) * 100) }
  get timerPercent() { return Math.round((this.timeLeft / (QUESTION_TIME_MS / 1000)) * 100) }
}

<template>
  <div class="max-w-lg mx-auto bg-white rounded-2xl shadow-lg p-6">
    {{#if this.loadQuiz.isRunning}}
      <p class="text-center text-gray-400 animate-pulse">Loading quiz...</p>
    {{else if this.quizDone}}
      <div class="text-center py-8">
        <div class="text-5xl mb-3">🏏</div>
        <h2 class="text-2xl font-bold">Quiz Complete!</h2>
        <p class="text-xl text-green-600 mt-2">{{this.score}} / {{this.questions.length}}</p>
      </div>
    {{else if this.currentQuestion}}
      <div class="mb-4">
        <div class="flex justify-between text-xs text-gray-400 mb-1">
          <span>Question {{add this.currentIndex 1}} / {{this.questions.length}}</span>
          <span class="{{if (lt this.timeLeft 6) "text-red-500 font-bold" "text-gray-400"}}">{{this.timeLeft}}s</span>
        </div>
        <div class="h-2 bg-gray-100 rounded-full mb-1">
          <div class="h-2 bg-green-400 rounded-full transition-all" style="width: {{this.progressPercent}}%"></div>
        </div>
        <div class="h-1.5 bg-gray-100 rounded-full">
          <div
            class="h-1.5 rounded-full transition-all
              {{if (lt this.timeLeft 6) "bg-red-400" "bg-yellow-400"}}"
            style="width: {{this.timerPercent}}%"
          ></div>
        </div>
      </div>
      <h3 class="font-semibold text-gray-800 mb-5">{{this.currentQuestion.text}}</h3>
      <div class="grid grid-cols-2 gap-3">
        {{#each this.currentQuestion.choices as |choice|}}
          <button
            {{on "click" (fn this.answer choice)}}
            disabled={{or this.selectedAnswer this.runQuestion.isIdle}}
            class="py-3 px-4 rounded-xl border-2 text-sm font-medium transition-colors
              {{if (eq this.selectedAnswer choice)
                (if (eq choice this.currentQuestion.correctAnswer) "border-green-500 bg-green-50 text-green-700" "border-red-500 bg-red-50 text-red-700")
                (if (and this.selectedAnswer (eq choice this.currentQuestion.correctAnswer)) "border-green-500 bg-green-50" "border-gray-200 hover:border-green-300")}}"
          >{{choice}}</button>
        {{/each}}
      </div>
    {{else}}
      <button {{on "click" (perform this.loadQuiz @tournamentId)}} class="w-full bg-green-600 text-white rounded-xl py-3 font-medium">Start Quiz</button>
    {{/if}}
  </div>
</template>
```

Two cooperating tasks: `loadQuiz` fetches questions, then immediately starts `runQuestion`. The `runQuestion` task counts down with a per-second `await timeout(1000)` loop, updating `@tracked timeLeft` for the timer bar. When the user answers, `runQuestion.cancelAll()` stops the countdown and `setTimeout` (native, not a task) advances after 2s of showing the result. `restartable` ensures calling `runQuestion.perform()` for the next question cleanly cancels any leftover state.

