import Component from '@glimmer/component'
import { task, all } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'

export default class TeamComparison extends Component {
  @tracked teamA = null
  @tracked teamB = null

  fetchTeam = task(async (teamId) => {
    const res = await fetch(`/api/teams/${teamId}/stats`)
    if (!res.ok) throw new Error(`Failed to load team ${teamId}`)
    return await res.json()
  })

  loadComparison = task({ drop: true }, async (teamAId, teamBId) => {
    this.teamA = null
    this.teamB = null
    // Fetch both in parallel — if either fails, both are cancelled
    const [a, b] = await all([
      this.fetchTeam.perform(teamAId),
      this.fetchTeam.perform(teamBId)
    ])
    this.teamA = a
    this.teamB = b
  })

  stat(team, key) { return team?.[key] ?? '—' }
}

