ember-concurrency's `all()` receives two `TaskInstance` objects from `this.fetchTeam.perform()`. If either fetch fails, the other is automatically cancelled — preventing one successful fetch from waiting orphaned. The comparison grid uses a 3-column layout (teamA | label | teamB) and highlights the winning value in colour using `gt` comparisons. The `stat()` helper method handles missing values gracefully.

```gjs
import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

export default class DrsReview extends Component {
  @tracked reviewsLeft = this.args.initialReviews ?? 2
  @tracked lastResult = null
  @tracked reviewHistory = []

  submitReview = task({ drop: true }, async (matchId, team, decision) => {
    this.lastResult = null
    const prevReviews = this.reviewsLeft
    this.reviewsLeft = Math.max(0, this.reviewsLeft - 1)  // optimistic decrement
    try {
      const res = await fetch(`/api/matches/${matchId}/drs`, {
        method: 'POST',
        body: JSON.stringify({ team, decision }),
        headers: { 'Content-Type': 'application/json' }
      })
      if (!res.ok) throw new Error(`DRS request failed (HTTP ${res.status})`)
      const data = await res.json()
      this.lastResult = data.outcome  // 'upheld' | 'overturned'
      // Restore review if overturned
      if (data.outcome === 'overturned') {
        this.reviewsLeft = prevReviews  // ✅ review returned
      }
      this.reviewHistory = [{ team, decision, outcome: data.outcome }, ...this.reviewHistory]
    } catch (err) {
      this.reviewsLeft = prevReviews  // ✅ rollback on error
      throw err
    }
  })

  get canReview() { return this.reviewsLeft > 0 && !this.submitReview.isRunning }
}

<template>
  <div class="bg-gray-900 text-white rounded-2xl p-5 max-w-sm">
    <div class="flex justify-between items-center mb-4">
      <h2 class="font-bold">DRS Review</h2>
      <span class="text-sm">
        {{#each (array 1 2 3) as |i|}}
          <span class="{{if (lte i this.reviewsLeft) "text-green-400" "text-gray-600"}}">●</span>
        {{/each}}
        {{this.reviewsLeft}} remaining
      </span>
    </div>
    {{#if this.lastResult}}
      <div class="mb-4 text-center py-3 rounded-xl
        {{if (eq this.lastResult "overturned") "bg-green-800" "bg-red-900"}}">
        <p class="text-lg font-bold">{{this.lastResult}}</p>
        {{#if (eq this.lastResult "overturned")}}<p class="text-xs text-green-300">Review retained</p>{{/if}}
      </div>
    {{/if}}
    {{#if this.submitReview.last.error}}
      <p class="text-red-400 text-xs mb-3">{{this.submitReview.last.error.message}}</p>
    {{/if}}
    <div class="grid grid-cols-2 gap-2">
      <button
        {{on "click" (perform this.submitReview @matchId "batting" "lbw")}}
        disabled={{not this.canReview}}
        class="bg-green-700 hover:bg-green-600 disabled:opacity-30 rounded-xl py-3 text-sm font-medium"
      >LBW Review</button>
      <button
        {{on "click" (perform this.submitReview @matchId "batting" "catch")}}
        disabled={{not this.canReview}}
        class="bg-blue-700 hover:bg-blue-600 disabled:opacity-30 rounded-xl py-3 text-sm font-medium"
      >Catch Review</button>
    </div>
    {{#if this.reviewHistory.length}}
      <div class="mt-4 space-y-1">
        {{#each this.reviewHistory as |r|}}
          <div class="flex justify-between text-xs text-gray-400">
            <span>{{r.team}} · {{r.decision}}</span>
            <span class="{{if (eq r.outcome "overturned") "text-green-400" "text-red-400"}}">{{r.outcome}}</span>
          </div>
        {{/each}}
      </div>
    {{/if}}
  </div>
</template>
```

Optimistic decrement provides instant feedback when a review is submitted. If the server returns an error, the rollback in the `catch` block restores the original `reviewsLeft`. If the review is `overturned`, the server indicates the review should be returned — this business logic is in the success path, not rollback. The `drop` policy prevents submitting multiple simultaneous DRS requests.

