import Component from '@glimmer/component'
import { task } from 'ember-concurrency'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'

const BID_INCREMENTS = [10, 25, 50, 100]

export default class PlayerAuctionBidder extends Component {
  @tracked currentBid = this.args.startingPrice ?? 100
  @tracked budget = this.args.budget ?? 5000
  @tracked bidHistory = []
  @tracked wonPlayer = null
  @tracked customIncrement = 50

  placeBid = task({ drop: true }, async (auctionId, amount) => {
    const res = await fetch(`/api/auctions/${auctionId}/bid`, {
      method: 'POST',
      body: JSON.stringify({ amount }),
      headers: { 'Content-Type': 'application/json' }
    })
    if (!res.ok) {
      const err = await res.json().catch(() => ({}))
      throw new Error(err.message ?? `Bid failed (HTTP ${res.status})`)
    }
    const data = await res.json()
    this.bidHistory = [{ amount, time: new Date().toLocaleTimeString(), status: data.status }, ...this.bidHistory]
    if (data.status === 'won') {
      this.wonPlayer = this.args.player
      this.budget -= amount
    } else {
      this.currentBid = data.nextMinimumBid
    }
  })

  @action setBid(increment) {
    const newBid = this.currentBid + increment
    if (newBid <= this.budget) this.currentBid = newBid
  }

  get canBid() {
    return this.currentBid <= this.budget && !this.wonPlayer && !this.placeBid.isRunning
  }

  get budgetPercent() {
    return Math.round((this.budget / (this.args.budget ?? 5000)) * 100)
  }
}

<template>
  <div class="bg-gradient-to-br from-gray-900 to-gray-800 text-white rounded-2xl p-5 max-w-sm">
    <div class="flex justify-between items-start mb-5">
      <div>
