      </div>
      <div class="text-right">
        <p class="text-xs text-gray-400">Budget</p>
        <p class="font-bold text-green-400">₹{{this.budget}}L</p>
        <div class="w-20 h-1 bg-gray-700 rounded mt-1">
          <div class="h-1 bg-green-400 rounded" style="width: {{this.budgetPercent}}%"></div>
        </div>
      </div>
    </div>
    {{#if this.wonPlayer}}
      <div class="bg-green-700 rounded-xl p-4 text-center mb-4">
        <p class="text-2xl">🏆</p>
        <p class="font-bold mt-1">Won {{this.wonPlayer.name}}!</p>
      </div>
    {{else}}
      <div class="text-center mb-5">
        <p class="text-xs text-gray-400">Your Bid</p>
        <p class="text-4xl font-bold text-yellow-400">₹{{this.currentBid}}L</p>
      </div>
      <div class="flex gap-2 mb-4">
        {{#each BID_INCREMENTS as |inc|}}
          <button {{on "click" (fn this.setBid inc)}} class="flex-1 bg-gray-700 hover:bg-gray-600 rounded-lg py-2 text-xs">+{{inc}}</button>
        {{/each}}
      </div>
      <button
        {{on "click" (perform this.placeBid @auctionId this.currentBid)}}
        disabled={{not this.canBid}}
        class="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-bold rounded-xl py-3 disabled:opacity-40"
      >
        {{#if this.placeBid.isRunning}}Placing Bid...{{else}}Place Bid ₹{{this.currentBid}}L{{/if}}
      </button>
    {{/if}}
    {{#if this.placeBid.last.error}}
      <p class="text-red-400 text-xs mt-2 text-center">{{this.placeBid.last.error.message}}</p>
    {{/if}}
    {{#if this.bidHistory.length}}
      <div class="mt-4 border-t border-gray-700 pt-3 space-y-1">
