export default class MatchResultRecorder extends Component {
  @tracked winner = ''
  @tracked margin = ''
  @tracked marginType = 'runs'
  @tracked notes = ''
  @tracked step = 'form'  // 'form' | 'confirm' | 'done'

  get resultSummary() {
    return `${this.winner} won by ${this.margin} ${this.marginType}`
  }

  get isFormValid() {
    return this.winner.trim() && this.margin.trim() && Number(this.margin) > 0
  }

