        <h2 class="font-bold text-gray-800 mb-4">Confirm Result</h2>
        <div class="bg-green-50 border border-green-200 rounded-xl p-4 mb-5">
          <p class="text-lg font-bold text-green-800">{{this.resultSummary}}</p>
