```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, all } from 'ember-concurrency'

export default class NrrCalculatorComponent extends Component {
  @tracked matchResults = []
  @tracked nrr = null
  @tracked error = null

  get formattedNrr() {
    if (this.nrr === null) return '--'
    return (this.nrr >= 0 ? '+' : '') + this.nrr.toFixed(3)
  }

  get nrrColor() {
    if (this.nrr === null) return 'text-gray-400'
    return this.nrr >= 0 ? 'text-green-500' : 'text-red-500'
  }

  loadNrr = task(async () => {
    this.error = null
    const matchIds = this.args.matchIds ?? []
    const fetches = matchIds.map(id =>
      fetch(`/api/matches/${id}/result`).then(r => r.json())
    )
    const results = await all(fetches)
    this.matchResults = results
    const totalRunsScored = results.reduce((sum, m) => sum + m.runsScored, 0)
    const totalOversFaced = results.reduce((sum, m) => sum + m.oversFaced, 0)
    const totalRunsConceded = results.reduce((sum, m) => sum + m.runsConceded, 0)
    const totalOversBowled = results.reduce((sum, m) => sum + m.oversBowled, 0)
    this.nrr =
      totalRunsScored / totalOversFaced - totalRunsConceded / totalOversBowled
  })

  <template>
    <div class="p-6 bg-white rounded-xl shadow">
      <h2 class="text-lg font-bold text-gray-800 mb-4">Net Run Rate</h2>
      {{#if this.loadNrr.isRunning}}
        <div class="text-gray-400 animate-pulse">Computing NRR...</div>
      {{else if this.error}}
        <div class="text-red-500">{{this.error}}</div>
      {{else}}
        <div class="text-4xl font-mono font-bold {{this.nrrColor}}">
          {{this.formattedNrr}}
        </div>
        <p class="text-sm text-gray-500 mt-1">Based on {{this.matchResults.length}} matches</p>
      {{/if}}
      <button
        class="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
        disabled={{this.loadNrr.isRunning}}
        {{on "click" (perform this.loadNrr)}}
      >
        {{if this.loadNrr.isRunning "Loading..." "Calculate NRR"}}
      </button>
    </div>
  </template>
}
```

This component uses `all()` to fetch multiple match results in parallel, then computes NRR using the standard formula: (runs scored / overs faced) minus (runs conceded / overs bowled). The `formattedNrr` getter prepends a `+` sign for positive values. `nrrColor` dynamically styles the display green or red based on the NRR sign. The button is disabled while the task runs to prevent duplicate requests.

