import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class VenueWeatherComponent extends Component {
  @tracked weather = null
  @tracked attempts = 0
  @tracked error = null
  MAX_RETRIES = 3

  fetchWeather = task(async () => {
    this.error = null
    this.attempts = 0
    while (this.attempts < this.MAX_RETRIES) {
      try {
        const response = await fetch(`/api/venues/${this.args.venueId}/weather`)
        if (!response.ok) throw new Error(`HTTP ${response.status}`)
