        this.attempts++
        if (this.attempts >= this.MAX_RETRIES) {
          this.error = `Failed after ${this.MAX_RETRIES} attempts: ${e.message}`
          return
        }
        await timeout(1000 * this.attempts)
      }
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.fetchWeather.perform()
  }

  <template>
    <div class="bg-gradient-to-br from-sky-400 to-blue-600 text-white rounded-2xl p-6 shadow-lg w-72">
      <h3 class="font-semibold text-sm uppercase tracking-widest mb-2">{{this.args.venueName}}</h3>
