import { task, timeout } from 'ember-concurrency'

export default class LiveMatchAlertComponent extends Component {
  @tracked currentRuns = 0
  @tracked threshold = 100
  @tracked alertFired = false
  @tracked isWatching = false

  @action
  updateThreshold(event) {
    this.threshold = Number(event.target.value)
    this.alertFired = false
  }

  pollScore = task(async () => {
    this.isWatching = true
    this.alertFired = false
    while (true) {
