import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class PlayerMilestoneTrackerComponent extends Component {
  @tracked milestones = []
  @tracked loadError = null
  @tracked saveError = null

  get achievedCount() {
    return this.milestones.filter(m => m.achieved).length
  }

  loadMilestones = task(async () => {
    this.loadError = null
    const response = await fetch(`/api/players/${this.args.playerId}/milestones`)
    if (!response.ok) throw new Error('Failed to load milestones')
    this.milestones = await response.json()
  })

  saveMilestone = task(async (milestoneId) => {
    this.saveError = null
    const response = await fetch(`/api/milestones/${milestoneId}/achieve`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ achieved: true })
    })
