import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task, timeout } from 'ember-concurrency'

export default class CommentarySearchComponent extends Component {
  @tracked query = ''
  @tracked results = []
  @tracked searchError = null

  get hasResults() {
    return this.results.length > 0
  }

  highlightText(text, query) {
    if (!query.trim()) return text
    const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
    return text.replace(new RegExp(`(${escaped})`, 'gi'), '<mark class="bg-yellow-200 rounded px-0.5">$1</mark>')
  }

  @action
  updateQuery(event) {
    this.query = event.target.value
    this.searchTask.perform(this.query)
  }

  searchTask = task({ restartable: true }, async (query) => {
    this.searchError = null
    await timeout(300)
    if (!query.trim()) {
      this.results = []
      return
    }
    const response = await fetch(`/api/matches/${this.args.matchId}/commentary?q=${encodeURIComponent(query)}`)
    if (!response.ok) throw new Error('Search failed')
    this.results = await response.json()
  })

  <template>
    <div class="max-w-2xl mx-auto p-4">
      <div class="relative mb-4">
        <input
          type="text"
          placeholder="Search commentary..."
          value={{this.query}}
          class="w-full border border-gray-300 rounded-xl px-4 py-3 pl-10 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
          {{on "input" this.updateQuery}}
        />
        <span class="absolute left-3 top-3.5 text-gray-400">🔍</span>
        {{#if this.searchTask.isRunning}}
          <span class="absolute right-3 top-3.5 text-xs text-gray-400 animate-pulse">Searching...</span>
        {{/if}}
      </div>
      {{#if this.searchError}}
        <div class="text-red-500 text-sm">{{this.searchError}}</div>
      {{else if this.hasResults}}
        <ul class="space-y-2">
          {{#each this.results as |commentary|}}
            <li class="bg-white rounded-xl shadow-sm p-4">
              <div class="text-xs text-gray-400 mb-1">Over {{commentary.over}} • Ball {{commentary.ball}}</div>
              <div class="text-sm text-gray-800" data-html={{this.highlightText commentary.text this.query}}></div>
            </li>
          {{/each}}
        </ul>
      {{else if (and this.query (not this.searchTask.isRunning))}}
