export default class FieldingPositionAssignerComponent extends Component {
  @tracked assignments = {}
  @tracked saveSuccess = false
  @tracked saveError = null
  positions = POSITIONS

  get unassignedPlayers() {
    const assigned = new Set(Object.values(this.assignments))
    return (this.args.players ?? []).filter(p => !assigned.has(p.id))
