    if (!playerId) {
      const { [position]: _, ...rest } = this.assignments
      this.assignments = rest
    } else {
      this.assignments = { ...this.assignments, [position]: playerId }
    }
    this.saveSuccess = false
  }

  saveTask = task({ drop: true }, async () => {
    this.saveError = null
    this.saveSuccess = false
    const response = await fetch(`/api/matches/${this.args.matchId}/fielding`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ assignments: this.assignments })
    })
