              {{on "change" (fn this.assignPlayer position)}}
            >
              <option value="">-- Select player --</option>
              {{#each this.args.players as |player|}}
                <option
                  value={{player.id}}
                  selected={{eq (get this.assignments position) player.id}}
                >{{player.name}}</option>
              {{/each}}
            </select>
          </div>
        {{/each}}
      </div>
      <div class="text-xs text-gray-400 mb-3">
        {{Object.keys(this.assignments).length}} / {{this.positions.length}} positions filled
      </div>
      {{#if this.saveSuccess}}
        <div class="text-green-600 text-sm mb-2">✅ Saved successfully!</div>
      {{/if}}
      {{#if this.saveError}}
        <div class="text-red-500 text-sm mb-2">{{this.saveError}}</div>
      {{/if}}
      <button
        class="w-full py-2 bg-green-600 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-green-700"
