import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class PartnershipTrackerComponent extends Component {
  @tracked partnerships = []
  @tracked batsman1 = ''
  @tracked batsman2 = ''
  @tracked runs = ''
  @tracked balls = ''
  @tracked addError = null

  get topPartnership() {
    return this.partnerships.reduce(
      (top, p) => (p.runs > (top?.runs ?? -1) ? p : top),
      null
    )
  }

  loadPartnerships = task(async () => {
    const response = await fetch(`/api/innings/${this.args.inningsId}/partnerships`)
    if (!response.ok) throw new Error('Load failed')
    this.partnerships = await response.json()
  })

  savePartnership = task(async (partnership) => {
    this.addError = null
    const response = await fetch(`/api/innings/${this.args.inningsId}/partnerships`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(partnership)
    })
    if (!response.ok) {
      this.partnerships = this.partnerships.slice(0, -1)
      this.addError = 'Failed to save partnership'
      return
    }
    const saved = await response.json()
    this.partnerships = [...this.partnerships.slice(0, -1), saved]
  })

  @action
  addPartnership() {
    if (!this.batsman1 || !this.batsman2 || !this.runs) return
    const partnership = {
      id: `temp-${Date.now()}`,
      batsman1: this.batsman1,
      batsman2: this.batsman2,
      runs: Number(this.runs),
      balls: Number(this.balls)
    }
    this.partnerships = [...this.partnerships, partnership]
    this.batsman1 = ''
    this.batsman2 = ''
    this.runs = ''
    this.balls = ''
    this.savePartnership.perform(partnership)
  }

  constructor(owner, args) {
    super(owner, args)
    this.loadPartnerships.perform()
  }

  <template>
    <div class="max-w-lg mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 text-lg mb-4">🤝 Partnerships</h2>
