import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

export default class MatchShareModalComponent extends Component {
  @tracked shortUrl = null
  @tracked copySuccess = false
  @tracked generateError = null

  generateUrl = task({ drop: true }, async () => {
    this.generateError = null
    this.shortUrl = null
    this.copySuccess = false
    const response = await fetch('/api/share/shorten', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ matchId: this.args.matchId })
    })
    if (!response.ok) {
      this.generateError = 'Could not generate share link'
      return
    }
    const { url } = await response.json()
    this.shortUrl = url
  })

  copyTask = task({ drop: true }, async () => {
    if (!this.shortUrl) return
    await navigator.clipboard.writeText(this.shortUrl)
    this.copySuccess = true
    await new Promise(resolve => setTimeout(resolve, 2000))
    this.copySuccess = false
  })

  <template>
    <div class="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
      <div class="bg-white rounded-2xl shadow-2xl p-6 w-96">
        <div class="flex items-center justify-between mb-4">
