        </div>
        <p class="text-sm text-gray-600 mb-4">Generate a short link to share this match with friends.</p>
        {{#if this.generateError}}
          <div class="text-red-500 text-sm mb-3">{{this.generateError}}</div>
        {{/if}}
        {{#if this.shortUrl}}
          <div class="flex gap-2 mb-4">
            <input
              type="text"
              value={{this.shortUrl}}
              readonly
              class="flex-1 border border-gray-300 rounded-lg px-3 py-2 text-sm bg-gray-50 font-mono"
            />
            <button
              class="px-4 py-2 rounded-lg text-sm font-medium transition-colors
                {{if this.copySuccess 'bg-green-500 text-white' 'bg-gray-100 hover:bg-gray-200 text-gray-700'}}"
              {{on "click" (perform this.copyTask)}}
            >
              {{if this.copySuccess '✅ Copied' '📋 Copy'}}
            </button>
          </div>
        {{/if}}
        <button
          class="w-full py-2 bg-blue-600 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-blue-700"
          disabled={{this.generateUrl.isRunning}}
