import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class PlayerInjuryLoggerComponent extends Component {
  @tracked injuries = []
  @tracked bodyPart = ''
  @tracked severity = 'minor'
  @tracked notes = ''
  @tracked saveError = null
  @tracked loadError = null

  get recentInjuries() {
    return [...this.injuries].sort((a, b) => new Date(b.loggedAt) - new Date(a.loggedAt))
  }

  loadInjuries = task(async () => {
    this.loadError = null
    const response = await fetch(`/api/players/${this.args.playerId}/injuries`)
    if (!response.ok) {
      this.loadError = 'Failed to load injury history'
      return
    }
    this.injuries = await response.json()
  })

  saveInjury = task({ drop: true }, async () => {
    if (!this.bodyPart) return
    this.saveError = null
    const newInjury = {
      id: `temp-${Date.now()}`,
      bodyPart: this.bodyPart,
      severity: this.severity,
      notes: this.notes,
      loggedAt: new Date().toISOString()
    }
    this.injuries = [...this.injuries, newInjury]
    this.bodyPart = ''
    this.notes = ''
    const response = await fetch(`/api/players/${this.args.playerId}/injuries`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newInjury)
    })
    if (!response.ok) {
      this.injuries = this.injuries.filter(i => i.id !== newInjury.id)
      this.saveError = 'Failed to save injury'
      return
    }
    const saved = await response.json()
    this.injuries = this.injuries.map(i => (i.id === newInjury.id ? saved : i))
  })

  @action
  logInjury() {
    this.saveInjury.perform()
  }

  constructor(owner, args) {
    super(owner, args)
    this.loadInjuries.perform()
  }

