import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

const MAX_CHARS = 280

export default class LiveCommentaryInserterComponent extends Component {
  @tracked newComment = ''
  @tracked commentaryList = []
  @tracked insertError = null

  get charCount() {
    return this.newComment.length
  }

  get charsRemaining() {
    return MAX_CHARS - this.charCount
  }

  get isOverLimit() {
    return this.charCount > MAX_CHARS
  }

  get canInsert() {
    return this.newComment.trim().length > 0 && !this.isOverLimit && !this.insertTask.isRunning
  }

  @action
  updateComment(event) {
    this.newComment = event.target.value
  }

  insertTask = task({ drop: true }, async () => {
    this.insertError = null
    const commentText = this.newComment.trim()
    const tempEntry = {
      id: `temp-${Date.now()}`,
      text: commentText,
      over: this.args.currentOver,
      ball: this.args.currentBall,
      insertedAt: new Date().toISOString()
    }
    this.commentaryList = [tempEntry, ...this.commentaryList]
    this.newComment = ''
    const response = await fetch(`/api/matches/${this.args.matchId}/commentary`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: commentText, over: tempEntry.over, ball: tempEntry.ball })
    })
    if (!response.ok) {
      this.commentaryList = this.commentaryList.filter(c => c.id !== tempEntry.id)
      this.newComment = commentText
      this.insertError = 'Failed to insert commentary'
      return
    }
    const saved = await response.json()
    this.commentaryList = this.commentaryList.map(c => (c.id === tempEntry.id ? saved : c))
  })

  <template>
    <div class="max-w-xl mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 text-lg mb-4">🎙️ Commentary Inserter</h2>
      <div class="mb-4">
        <textarea
          rows="3"
          placeholder="Type commentary for this ball..."
          class="w-full border rounded-xl px-3 py-2 text-sm resize-none focus:outline-none focus:ring-2
            {{if this.isOverLimit 'border-red-400 focus:ring-red-300' 'border-gray-300 focus:ring-blue-400'}}"
          {{on "input" this.updateComment}}
        >{{this.newComment}}</textarea>
        <div class="flex justify-between items-center mt-1">
          <span class="text-xs {{if this.isOverLimit 'text-red-500' 'text-gray-400'}}">
            {{this.charsRemaining}} characters remaining
          </span>
          <span class="text-xs text-gray-400">Over {{this.args.currentOver}}.{{this.args.currentBall}}</span>
        </div>
      </div>
      {{#if this.insertError}}
        <div class="text-red-500 text-xs mb-3">{{this.insertError}}</div>
      {{/if}}
      <button
        class="w-full py-2 mb-5 bg-blue-600 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-blue-700"
        disabled={{not this.canInsert}}
        {{on "click" (perform this.insertTask)}}
      >Insert Commentary</button>
      <h3 class="font-semibold text-gray-700 text-sm mb-3">Recent Commentary</h3>
      <ul class="space-y-2 max-h-64 overflow-y-auto">
        {{#each this.commentaryList as |entry|}}
          <li class="bg-gray-50 rounded-xl px-4 py-3">
            <div class="flex items-center gap-2 mb-1">
              <span class="text-xs font-mono text-blue-600">{{entry.over}}.{{entry.ball}}</span>
              <span class="text-xs text-gray-400">{{entry.insertedAt}}</span>
            </div>
            <p class="text-sm text-gray-800">{{entry.text}}</p>
          </li>
        {{/each}}
      </ul>
    </div>
  </template>
}
```

Commentary is prepended optimistically before the API call and rolled back (removed from list, text restored) if the save fails. The character counter turns red when over the 280-char limit. The `drop` modifier on `insertTask` prevents overlapping submissions during rapid clicks. The list is capped with `max-h-64 overflow-y-auto` to stay scrollable.

