    this.saveError = null
    const response = await fetch(`/api/players/${this.args.playerId}/availability`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(this.availability)
    })
    if (!response.ok) this.saveError = 'Failed to save availability'
  })

  @action
  toggleDay(day) {
    this.availability = {
      ...this.availability,
      [day]: !this.availability[day]
    }
    this.saveAvailability.perform()
  }

  constructor(owner, args) {
    super(owner, args)
    this.loadAvailability.perform()
  }

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 text-lg mb-4">📅 Availability — {{this.args.playerName}}</h2>
      {{#if this.loadAvailability.isRunning}}
        <div class="text-gray-400 animate-pulse">Loading calendar...</div>
      {{else if this.loadError}}
        <div class="text-red-500 text-sm">{{this.loadError}}</div>
      {{else}}
        <div class="grid grid-cols-7 gap-1">
          {{#each this.days as |day|}}
            <button
              class="flex flex-col items-center p-2 rounded-xl border-2 transition-all text-xs
                {{if (get this.availability day)
                  'border-green-400 bg-green-50 text-green-700'
                  'border-gray-200 text-gray-400 hover:border-gray-300'}}"
              {{on "click" (fn this.toggleDay day)}}
            >
              <span>{{slice day 8 10}}</span>
              <span class="text-lg mt-0.5">{{if (get this.availability day) '✅' '❌'}}</span>
            </button>
          {{/each}}
        </div>
      {{/if}}
      {{#if this.saveError}}
        <div class="text-red-500 text-xs mt-3">{{this.saveError}}</div>
      {{/if}}
      {{#if this.saveAvailability.isRunning}}
        <div class="text-xs text-gray-400 mt-2 text-center animate-pulse">Saving...</div>
      {{/if}}
    </div>
  </template>
}
```

The `days` getter computes a 7-day window from `weekStart`, keeping the component stateless about dates. Toggling a day immediately updates the `availability` object immutably for instant visual feedback, then triggers `saveAvailability`. The `drop` modifier prevents overlapping saves if the user rapidly toggles multiple days. Each day button uses `get` helper to look up the date key in the availability object.

