```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task, timeout } from 'ember-concurrency'

export default class MatchChatComponent extends Component {
  @tracked messages = []
  @tracked composingText = ''
  @tracked isPolling = false

  get canSend() {
    return this.composingText.trim().length > 0 && !this.sendTask.isRunning
  }

  @action
  updateText(event) {
    this.composingText = event.target.value
  }

  pollMessages = task(async () => {
    this.isPolling = true
    while (true) {
      const response = await fetch(`/api/matches/${this.args.matchId}/chat?since=${this.lastMessageId ?? 0}`)
      if (response.ok) {
        const newMessages = await response.json()
        if (newMessages.length > 0) {
          this.messages = [...this.messages, ...newMessages]
        }
      }
      await timeout(3000)
    }
  })

  get lastMessageId() {
    return this.messages.at(-1)?.id ?? null
  }

  sendTask = task({ drop: true }, async () => {
    const text = this.composingText.trim()
    if (!text) return
    this.composingText = ''
    const response = await fetch(`/api/matches/${this.args.matchId}/chat`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text, userId: this.args.userId })
    })
    if (response.ok) {
      const message = await response.json()
      this.messages = [...this.messages, message]
    } else {
      this.composingText = text
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.pollMessages.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.pollMessages.cancelAll()
  }

  <template>
    <div class="flex flex-col h-96 bg-white rounded-2xl shadow">
      <div class="px-4 py-3 border-b flex items-center justify-between">
        <h3 class="font-semibold text-gray-800">💬 Match Chat</h3>
        <span class="text-xs text-green-500 animate-pulse">● Live</span>
      </div>
      <div class="flex-1 overflow-y-auto p-4 space-y-2">
        {{#each this.messages as |message|}}
          <div class="{{if (eq message.userId this.args.userId) 'flex flex-col items-end' ''}}">
            <span class="text-xs text-gray-400 mb-0.5">{{message.username}}</span>
            <div class="px-3 py-2 rounded-2xl text-sm max-w-xs
              {{if (eq message.userId this.args.userId)
                'bg-blue-600 text-white'
                'bg-gray-100 text-gray-800'}}">
              {{message.text}}
            </div>
          </div>
        {{/each}}
      </div>
      <div class="p-3 border-t flex gap-2">
        <input
          type="text"
          placeholder="Type a message..."
          value={{this.composingText}}
          class="flex-1 border border-gray-300 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400"
          {{on "input" this.updateText}}
          {{on "keydown" (fn (action (if (eq key 'Enter') (perform this.sendTask))))}}
        />
        <button
          class="px-4 py-2 bg-blue-600 text-white rounded-full text-sm disabled:opacity-50 hover:bg-blue-700"
          disabled={{not this.canSend}}
          {{on "click" (perform this.sendTask)}}
        >Send</button>
      </div>
    </div>
  </template>
}
```

Polling uses a `since` query parameter to fetch only new messages since the last known ID, reducing bandwidth. The polling task is cancelled in `willDestroy` to prevent memory leaks. The `sendTask` uses `drop` to prevent message duplication from double-clicks. If the send fails, the text is restored to `composingText` so the user doesn't lose their message.

