export default class OverRateMonitorComponent extends Component {
  @tracked currentOver = 0
  @tracked elapsedMinutes = 0
  @tracked isSlowAlert = false
  REQUIRED_OVERS_PER_HOUR = 15

  get overRate() {
    if (this.elapsedMinutes === 0) return 0
    return (this.currentOver / this.elapsedMinutes) * 60
  }

  get overRateLabel() {
    return this.overRate.toFixed(1)
  }

  get overRateColor() {
    if (this.overRate >= this.REQUIRED_OVERS_PER_HOUR) return 'text-green-600'
    if (this.overRate >= this.REQUIRED_OVERS_PER_HOUR * 0.9) return 'text-yellow-500'
    return 'text-red-600'
  }

  monitorTask = task(async () => {
    while (true) {
      const response = await fetch(`/api/matches/${this.args.matchId}/live`)
      if (response.ok) {
        const data = await response.json()
        this.currentOver = data.currentOver
        this.elapsedMinutes = data.elapsedMinutes
        this.isSlowAlert = this.overRate < this.REQUIRED_OVERS_PER_HOUR
      }
      await timeout(10000)
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.monitorTask.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.monitorTask.cancelAll()
  }

  <template>
    <div class="bg-gray-900 text-white rounded-2xl p-5 w-56">
      <div class="flex items-center justify-between mb-3">
        <h3 class="font-semibold text-sm">⏱️ Over Rate</h3>
        {{#if this.monitorTask.isRunning}}
          <span class="text-xs text-green-400 animate-pulse">● Live</span>
        {{/if}}
      </div>
      <div class="text-center">
        <div class="text-5xl font-bold font-mono {{this.overRateColor}}">{{this.overRateLabel}}</div>
        <div class="text-xs text-gray-400 mt-1">overs/hour</div>
      </div>
      <div class="mt-3 text-xs text-gray-400 text-center">
        Over {{this.currentOver}} • {{this.elapsedMinutes}} min elapsed
      </div>
      <div class="mt-2 text-xs text-center text-gray-500">
        Required: {{this.REQUIRED_OVERS_PER_HOUR}} overs/hr
      </div>
      {{#if this.isSlowAlert}}
        <div class="mt-3 bg-red-900/50 border border-red-700 rounded-lg px-3 py-2 text-xs text-red-300 text-center">
          ⚠️ Slow over rate! Risk of penalty.
        </div>
      {{/if}}
    </div>
  </template>
}
