import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, all } from 'ember-concurrency'

export default class ScoreDifferenceBadgeComponent extends Component {
  @tracked scores = null
  @tracked loadError = null

  get homeScore() {
    return this.scores?.[0] ?? null
  }

  get awayScore() {
    return this.scores?.[1] ?? null
  }

  get diff() {
    if (!this.homeScore || !this.awayScore) return null
    return this.homeScore.totalRuns - this.awayScore.totalRuns
  }

  get diffLabel() {
    if (this.diff === null) return '--'
    if (this.diff === 0) return 'Level'
    const runs = Math.abs(this.diff)
    const leader = this.diff > 0 ? this.homeScore.teamName : this.awayScore.teamName
    return `${leader} lead by ${runs} runs`
  }

  get badgeColor() {
    if (this.diff === null) return 'bg-gray-100 text-gray-400'
    if (this.diff === 0) return 'bg-yellow-100 text-yellow-700'
    return this.diff > 0 ? 'bg-blue-100 text-blue-700' : 'bg-red-100 text-red-700'
  }

  loadScores = task(async () => {
    this.loadError = null
    const [homeMatch, awayMatch] = this.args.matchIds
    this.scores = await all([
      fetch(`/api/innings/${homeMatch}/score`).then(r => r.json()),
      fetch(`/api/innings/${awayMatch}/score`).then(r => r.json())
    ])
  })

  constructor(owner, args) {
    super(owner, args)
    this.loadScores.perform()
  }

