      {{else}}
        <div class="flex items-center gap-3 text-sm font-semibold">
          <span>{{this.homeScore.teamName}} {{this.homeScore.totalRuns}}/{{this.homeScore.wickets}}</span>
          <span class="text-gray-400 text-xs">vs</span>
          <span>{{this.awayScore.totalRuns}}/{{this.awayScore.wickets}} {{this.awayScore.teamName}}</span>
        </div>
        <div class="rounded-full px-4 py-1 text-xs font-medium {{this.badgeColor}}">{{this.diffLabel}}</div>
      {{/if}}
      <button
        class="text-xs text-gray-400 underline mt-1 hover:text-gray-600"
        {{on "click" (perform this.loadScores)}}
      >Refresh</button>
    </div>
  </template>
}
