import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task } from 'ember-concurrency'

const REACTIONS = [
  { emoji: '🔥', key: 'fire', label: 'On Fire' },
  { emoji: '👏', key: 'clap', label: 'Great Shot' },
  { emoji: '😱', key: 'shocked', label: 'Shocked' },
  { emoji: '😤', key: 'frustrate', label: 'Frustrating' },
  { emoji: '🎉', key: 'celebrate', label: 'Celebrate' }
]

export default class FanReactionBarComponent extends Component {
  @tracked counts = Object.fromEntries(REACTIONS.map(r => [r.key, 0]))
  reactions = REACTIONS

  get topReaction() {
    return Object.entries(this.counts).reduce(
      (top, [key, count]) => (count > top.count ? { key, count } : top),
      { key: null, count: -1 }
    )
  }

  reactTask = task({ drop: true }, async (reactionKey) => {
    this.counts = { ...this.counts, [reactionKey]: this.counts[reactionKey] + 1 }
    const response = await fetch(`/api/matches/${this.args.matchId}/reactions`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ reaction: reactionKey })
    })
    if (!response.ok) {
      this.counts = { ...this.counts, [reactionKey]: this.counts[reactionKey] - 1 }
    }
  })

  <template>
    <div class="bg-white rounded-2xl shadow p-4">
      <div class="flex gap-2 justify-center">
        {{#each this.reactions as |reaction|}}
          <button
            class="flex flex-col items-center gap-1 px-3 py-2 rounded-xl transition-all
              {{if (eq this.topReaction.key reaction.key)
                'bg-yellow-100 ring-2 ring-yellow-400 scale-110'
                'bg-gray-50 hover:bg-gray-100'}}"
            {{on "click" (fn (perform this.reactTask) reaction.key)}}
          >
            <span class="text-2xl">{{reaction.emoji}}</span>
            <span class="text-xs font-mono font-bold text-gray-700">{{get this.counts reaction.key}}</span>
            <span class="text-xs text-gray-400">{{reaction.label}}</span>
          </button>
        {{/each}}
      </div>
      {{#if this.topReaction.key}}
        <div class="text-center text-xs text-gray-500 mt-3">
          Top reaction: <strong>{{this.topReaction.key}}</strong> with {{this.topReaction.count}} taps
        </div>
      {{/if}}
    </div>
  </template>
}
```

Each button calls `perform this.reactTask` with its specific reaction key — since ember-concurrency task instances are concurrent by default, different reaction keys can be sent simultaneously. The `drop` modifier prevents the same reaction from double-firing within one task lifecycle. Optimistic counting increments immediately and rolls back if the API fails. The `topReaction` getter automatically highlights the leading reaction.

