    await timeout(800)
    this.saveStatus = 'saving'
    const response = await fetch(`/api/matches/${this.args.matchId}/notes`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ notes: this.notes })
    })
    this.saveStatus = response.ok ? 'saved' : 'error'
  })

  loadNotes = task(async () => {
    const response = await fetch(`/api/matches/${this.args.matchId}/notes`)
    if (response.ok) {
      const data = await response.json()
      this.notes = data.notes ?? ''
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.loadNotes.perform()
  }

  <template>
    <div class="max-w-xl mx-auto bg-white rounded-2xl shadow p-6">
      <div class="flex items-center justify-between mb-3">
        <h2 class="font-bold text-gray-800">📝 Match Notes</h2>
        <span class="text-xs {{this.statusColor}}">{{this.statusLabel}}</span>
      </div>
      {{#if this.loadNotes.isRunning}}
        <div class="h-48 bg-gray-50 rounded-xl animate-pulse"></div>
      {{else}}
        <textarea
          class="w-full h-48 border border-gray-300 rounded-xl px-4 py-3 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-blue-400"
          placeholder="Add match notes, observations, key moments..."
          {{on "input" this.updateNotes}}
        >{{this.notes}}</textarea>
      {{/if}}
