const DISMISSAL_TYPES = [
  { key: 'bowled', label: 'Bowled', icon: '🎳' },
  { key: 'caught', label: 'Caught', icon: '🤲' },
  { key: 'lbw', label: 'LBW', icon: '🦵' },
  { key: 'run_out', label: 'Run Out', icon: '🏃' },
  { key: 'stumped', label: 'Stumped', icon: '🧤' },
  { key: 'hit_wicket', label: 'Hit Wicket', icon: '🏏' },
  { key: 'obstructing', label: 'Obstructing Field', icon: '🚧' },
  { key: 'retired', label: 'Retired Hurt', icon: '🩹' }
]

export default class DismissalTypeRecorderComponent extends Component {
  @tracked dismissalType = null
  @tracked fielder = ''
  @tracked isSaved = false
  @tracked saveError = null
  dismissalTypes = DISMISSAL_TYPES

  get formattedDismissal() {
    if (!this.dismissalType) return 'Select a dismissal type'
    const type = this.dismissalTypes.find(d => d.key === this.dismissalType)
    if (!type) return this.dismissalType
    const needsFielder = ['caught', 'run_out', 'stumped'].includes(this.dismissalType)
    return needsFielder && this.fielder
      ? `${type.label} (${this.fielder})`
      : type.label
  }

  get showFielderInput() {
    return ['caught', 'run_out', 'stumped'].includes(this.dismissalType)
  }

  @action
  selectType(key) {
    if (this.isSaved) return
    this.dismissalType = key
    this.fielder = ''
    this.saveError = null
  }

  saveTask = task({ drop: true }, async () => {
    if (!this.dismissalType) return
    this.saveError = null
    const response = await fetch(`/api/deliveries/${this.args.deliveryId}/dismissal`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: this.dismissalType, fielder: this.fielder || null })
    })
    if (!response.ok) {
      this.saveError = 'Failed to record dismissal'
      return
    }
    this.isSaved = true
  })

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 text-lg mb-1">🏏 Dismissal Recorder</h2>
