```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task, timeout } from 'ember-concurrency'
import { service } from '@ember/service'

export default class SessionExpiryHandlerComponent extends Component {
  @service router
  @service session
  @tracked timeLeft = 0
  @tracked isExpired = false

  get formattedTime() {
    const minutes = Math.floor(this.timeLeft / 60)
    const seconds = this.timeLeft % 60
    return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`
  }

  get urgencyColor() {
    if (this.timeLeft > 60) return 'text-green-600'
    if (this.timeLeft > 30) return 'text-yellow-500'
    return 'text-red-600 animate-pulse'
  }

  get showWarning() {
    return this.timeLeft <= 60 && this.timeLeft > 0
  }

  countdownTask = task(async () => {
    this.timeLeft = this.args.durationSeconds ?? 1800
    while (this.timeLeft > 0) {
      await timeout(1000)
      this.timeLeft -= 1
    }
    this.isExpired = true
    await this.logoutTask.perform()
  })

  logoutTask = task({ drop: true }, async () => {
    await fetch('/api/auth/logout', { method: 'POST' })
    this.router.transitionTo('login')
  })

  @action
  extendSession() {
    this.timeLeft = this.args.durationSeconds ?? 1800
  }

  constructor(owner, args) {
    super(owner, args)
    this.countdownTask.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.countdownTask.cancelAll()
  }

  <template>
    <div class="fixed bottom-4 right-4 bg-white rounded-2xl shadow-xl p-4 w-64 border border-gray-100">
      <div class="flex items-center justify-between mb-2">
        <span class="text-xs font-semibold text-gray-500 uppercase tracking-wide">Session</span>
        {{#if this.isExpired}}
          <span class="text-xs text-red-600 font-bold">Expired</span>
        {{/if}}
      </div>
      <div class="text-4xl font-mono font-bold text-center {{this.urgencyColor}}">{{this.formattedTime}}</div>
      {{#if this.showWarning}}
        <div class="mt-2 text-xs text-red-500 text-center">⚠️ Session expiring soon!</div>
        <button
          class="mt-2 w-full py-1.5 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700"
          {{on "click" this.extendSession}}
        >Extend Session</button>
      {{/if}}
    </div>
  </template>
}
```

The countdown task decrements `timeLeft` by 1 every second using `timeout(1000)`. When it reaches zero, it sets `isExpired` and chains into `logoutTask` which calls the API and redirects. The `extendSession` action resets `timeLeft` without restarting the task — the existing loop picks up the new value naturally. Visual urgency escalates through green → yellow → red with pulsing at under 30 seconds.

