    const response = await fetch(`/api/users/${this.args.userId}/notifications?limit=10`)
    if (!response.ok) return
    this.notifications = await response.json()
  })

  markAllRead = task({ drop: true }, async () => {
    await fetch(`/api/users/${this.args.userId}/notifications/read-all`, { method: 'POST' })
    this.count = 0
    this.notifications = this.notifications.map(n => ({ ...n, read: true }))
  })

  @action
  toggleOpen() {
    this.isOpen = !this.isOpen
    if (this.isOpen) {
      this.fetchNotifications.perform()
      if (this.count > 0) this.markAllRead.perform()
    }
  }

  constructor(owner, args) {
    super(owner, args)
    this.fetchCount.perform()
  }

  <template>
