import { task, timeout } from 'ember-concurrency'

export default class SearchHistoryComponent extends Component {
  @tracked query = ''
  @tracked results = []
  @tracked history = []
  @tracked saveError = null

  @action
  updateQuery(event) {
    this.query = event.target.value
    this.searchTask.perform(this.query)
  }

  @action
  selectHistory(term) {
    this.query = term
    this.searchTask.perform(term)
  }

  @action
  clearHistory() {
    this.history = []
    fetch('/api/search-history', { method: 'DELETE' }).catch(() => {})
  }

  searchTask = task({ restartable: true }, async (q) => {
    await timeout(350)
    if (!q.trim()) {
      this.results = []
      return
    }
    const response = await fetch(`/api/players/search?q=${encodeURIComponent(q)}`)
    this.results = await response.json()
    const trimmed = q.trim()
    if (!this.history.includes(trimmed)) {
      this.history = [trimmed, ...this.history].slice(0, 10)
      this.saveHistory.perform()
    }
  })

  saveHistory = task({ restartable: true }, async () => {
    this.saveError = null
    await timeout(500)
    const response = await fetch('/api/search-history', {
