      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ history: this.history })
    })
    if (!response.ok) this.saveError = 'Could not save history'
  })

  loadHistory = task(async () => {
    const response = await fetch('/api/search-history')
    if (response.ok) {
