import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class RealTimeLeaderboardComponent extends Component {
  @tracked rankings = []
  @tracked previousRankings = []
  @tracked loadError = null

  getRankChange(teamId) {
    const prev = this.previousRankings.findIndex(r => r.teamId === teamId)
    const curr = this.rankings.findIndex(r => r.teamId === teamId)
    if (prev === -1) return null
    return prev - curr
  }

  pollRankings = task(async () => {
    while (true) {
      this.loadError = null
      const response = await fetch(`/api/tournaments/${this.args.tournamentId}/leaderboard`)
      if (response.ok) {
        const newRankings = await response.json()
        this.previousRankings = [...this.rankings]
        this.rankings = newRankings
      } else {
        this.loadError = 'Failed to refresh leaderboard'
      }
      await timeout(15000)
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.pollRankings.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.pollRankings.cancelAll()
  }

  <template>
    <div class="max-w-lg mx-auto bg-white rounded-2xl shadow p-6">
      <div class="flex items-center justify-between mb-4">
        <h2 class="font-bold text-gray-800 text-lg">🏆 Leaderboard</h2>
        <span class="text-xs text-green-500 animate-pulse">● Live</span>
      </div>
      {{#if this.loadError}}
        <div class="text-red-500 text-sm mb-3">{{this.loadError}}</div>
      {{/if}}
      {{#if this.rankings.length}}
        <ol class="space-y-2">
          {{#each this.rankings as |team index|}}
            {{#let (this.getRankChange team.teamId) as |change|}}
              <li class="flex items-center gap-3 p-3 rounded-xl
                {{if (and change (gt change 0)) 'bg-green-50'
                  (if (and change (lt change 0)) 'bg-red-50' 'bg-gray-50')}}">
                <span class="text-lg font-bold text-gray-400 w-6 text-center">{{add index 1}}</span>
                <span class="flex-1 font-medium text-gray-800">{{team.teamName}}</span>
                <span class="text-sm text-gray-600 font-mono">{{team.points}} pts</span>
                {{#if change}}
                  <span class="text-xs font-bold
                    {{if (gt change 0) 'text-green-600' (if (lt change 0) 'text-red-500' 'text-gray-400')}}">
                    {{if (gt change 0) '▲' (if (lt change 0) '▼' '–')}}{{abs change}}
                  </span>
                {{/if}}
              </li>
            {{/let}}
          {{/each}}
        </ol>
      {{else}}
        <div class="text-gray-400 text-sm text-center animate-pulse">Loading leaderboard...</div>
      {{/if}}
    </div>
  </template>
}
```

`previousRankings` is saved before each update, enabling `getRankChange` to compare old and new positions. A positive change (moved up) highlights the row green; negative (moved down) highlights red. The polling task saves the previous state atomically before assigning new rankings, preventing a render cycle where both are the same. Rows with no change show no indicator.

