import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class ScoreCorrectionSubmitterComponent extends Component {
  @tracked original = null
  @tracked correctedRuns = ''
  @tracked correctedWickets = ''
  @tracked correctedOvers = ''
  @tracked submitError = null
  @tracked isSubmitted = false

  get diff() {
    if (!this.original || !this.correctedRuns) return null
    return {
      runs: Number(this.correctedRuns) - this.original.runs,
      wickets: Number(this.correctedWickets) - this.original.wickets,
      overs: Number(this.correctedOvers) - this.original.overs
    }
  }

  get diffLabel() {
    if (!this.diff) return ''
    const parts = []
    if (this.diff.runs !== 0) parts.push(`${this.diff.runs > 0 ? '+' : ''}${this.diff.runs} runs`)
    if (this.diff.wickets !== 0) parts.push(`${this.diff.wickets > 0 ? '+' : ''}${this.diff.wickets} wkts`)
    if (this.diff.overs !== 0) parts.push(`${this.diff.overs > 0 ? '+' : ''}${this.diff.overs} ov`)
    return parts.length ? `Changes: ${parts.join(', ')}` : 'No changes'
  }

  get hasChanges() {
    return this.diff && (this.diff.runs !== 0 || this.diff.wickets !== 0 || this.diff.overs !== 0)
  }

  loadOriginal = task(async () => {
    const response = await fetch(`/api/innings/${this.args.inningsId}/score`)
    if (!response.ok) return
    const data = await response.json()
    this.original = data
    this.correctedRuns = String(data.runs)
    this.correctedWickets = String(data.wickets)
    this.correctedOvers = String(data.overs)
  })

  submitTask = task({ drop: true }, async () => {
    this.submitError = null
    const response = await fetch(`/api/innings/${this.args.inningsId}/correction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        runs: Number(this.correctedRuns),
        wickets: Number(this.correctedWickets),
        overs: Number(this.correctedOvers),
        reason: this.args.reason
      })
    })
    if (!response.ok) {
      this.submitError = 'Correction submission failed'
      return
    }
    this.isSubmitted = true
  })

  constructor(owner, args) {
    super(owner, args)
    this.loadOriginal.perform()
  }

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 text-lg mb-4">✏️ Score Correction</h2>
      {{#if this.loadOriginal.isRunning}}
        <div class="text-gray-400 animate-pulse">Loading original score...</div>
      {{else if this.isSubmitted}}
        <div class="text-green-600 text-center font-semibold">✅ Correction submitted!</div>
      {{else if this.original}}
        <div class="bg-gray-50 rounded-xl p-3 mb-4 text-sm">
          <span class="text-gray-500">Original: </span>
          <span class="font-mono font-bold">{{this.original.runs}}/{{this.original.wickets}} ({{this.original.overs}} ov)</span>
        </div>
        <div class="grid grid-cols-3 gap-3 mb-3">
          <div>
            <label class="text-xs text-gray-500 block mb-1">Runs</label>
            <input type="number" value={{this.correctedRuns}} class="w-full border rounded-lg px-2 py-1.5 text-sm"
              {{on "input" (fn (mut this.correctedRuns) value="target.value")}} />
          </div>
          <div>
            <label class="text-xs text-gray-500 block mb-1">Wickets</label>
            <input type="number" value={{this.correctedWickets}} class="w-full border rounded-lg px-2 py-1.5 text-sm"
              {{on "input" (fn (mut this.correctedWickets) value="target.value")}} />
          </div>
          <div>
            <label class="text-xs text-gray-500 block mb-1">Overs</label>
            <input type="number" step="0.1" value={{this.correctedOvers}} class="w-full border rounded-lg px-2 py-1.5 text-sm"
              {{on "input" (fn (mut this.correctedOvers) value="target.value")}} />
          </div>
        </div>
        <div class="text-xs text-blue-600 mb-4 min-h-4">{{this.diffLabel}}</div>
        {{#if this.submitError}}
          <div class="text-red-500 text-xs mb-3">{{this.submitError}}</div>
        {{/if}}
        <button
          class="w-full py-2 bg-orange-500 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-orange-600"
          disabled={{or (not this.hasChanges) this.submitTask.isRunning}}
          {{on "click" (perform this.submitTask)}}
        >
          {{if this.submitTask.isRunning "Submitting..." "Submit Correction"}}
        </button>
      {{/if}}
    </div>
  </template>
}
```

The `diff` getter computes signed deltas between original and corrected values, returning `null` when data is incomplete. `diffLabel` formats the diff as a human-readable string. The submit button disables when `hasChanges` is false (no actual changes made), preventing no-op API calls. Original values are pre-populated into the correction inputs for easy minor edits.

