import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class UndoRedoScoreEditorComponent extends Component {
  @tracked undoStack = []
  @tracked redoStack = []
  @tracked current = { runs: 0, wickets: 0, overs: 0 }
  @tracked savedState = null
  @tracked saveError = null

  get isDirty() {
    if (!this.savedState) return true
    return JSON.stringify(this.current) !== JSON.stringify(this.savedState)
  }

  get canUndo() { return this.undoStack.length > 0 }
  get canRedo() { return this.redoStack.length > 0 }

  @action
  updateField(field, event) {
    this.undoStack = [...this.undoStack, { ...this.current }]
    this.redoStack = []
    this.current = { ...this.current, [field]: Number(event.target.value) }
  }

  @action
  undo() {
    if (!this.canUndo) return
    this.redoStack = [...this.redoStack, { ...this.current }]
    this.current = this.undoStack.at(-1)
    this.undoStack = this.undoStack.slice(0, -1)
  }

  @action
  redo() {
    if (!this.canRedo) return
    this.undoStack = [...this.undoStack, { ...this.current }]
    this.current = this.redoStack.at(-1)
    this.redoStack = this.redoStack.slice(0, -1)
  }

  saveTask = task({ drop: true }, async () => {
    this.saveError = null
    const response = await fetch(`/api/innings/${this.args.inningsId}/score`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(this.current)
    })
    if (!response.ok) {
      this.saveError = 'Save failed'
      return
    }
    this.savedState = { ...this.current }
  })

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <div class="flex items-center justify-between mb-4">
        <h2 class="font-bold text-gray-800">📝 Score Editor</h2>
        {{#if this.isDirty}}
          <span class="text-xs text-orange-500 font-medium">● Unsaved changes</span>
        {{else}}
          <span class="text-xs text-green-500">✅ Saved</span>
        {{/if}}
      </div>
      <div class="grid grid-cols-3 gap-3 mb-4">
        {{#each (array
          (hash label="Runs" field="runs")
          (hash label="Wickets" field="wickets")
          (hash label="Overs" field="overs")
        ) as |item|}}
          <div>
            <label class="text-xs text-gray-500 block mb-1">{{item.label}}</label>
            <input
              type="number"
              value={{get this.current item.field}}
              class="w-full border border-gray-300 rounded-lg px-2 py-2 text-sm text-center font-mono"
              {{on "input" (fn this.updateField item.field)}}
            />
          </div>
        {{/each}}
      </div>
      <div class="flex gap-2 mb-4">
        <button
          class="flex-1 py-1.5 text-sm rounded-lg border border-gray-200 disabled:opacity-40 hover:bg-gray-50"
          disabled={{not this.canUndo}}
          {{on "click" this.undo}}
        >↩ Undo</button>
        <button
          class="flex-1 py-1.5 text-sm rounded-lg border border-gray-200 disabled:opacity-40 hover:bg-gray-50"
          disabled={{not this.canRedo}}
          {{on "click" this.redo}}
        >↪ Redo</button>
      </div>
      {{#if this.saveError}}
        <div class="text-red-500 text-xs mb-2">{{this.saveError}}</div>
      {{/if}}
      <button
        class="w-full py-2 bg-blue-600 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-blue-700"
        disabled={{or (not this.isDirty) this.saveTask.isRunning}}
        {{on "click" (perform this.saveTask)}}
      >
        {{if this.saveTask.isRunning "Saving..." "Save Score"}}
      </button>
    </div>
  </template>
}
