import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class InfiniteScrollFixtureListComponent extends Component {
  @tracked fixtures = []
  @tracked page = 1
  @tracked totalPages = 1
  @tracked loadError = null
  observer = null

  get hasMore() {
    return this.page < this.totalPages
  }

  loadPage = task({ drop: true }, async () => {
    this.loadError = null
    const response = await fetch(
      `/api/fixtures?page=${this.page}&limit=10&tournamentId=${this.args.tournamentId}`
    )
    if (!response.ok) {
      this.loadError = 'Failed to load fixtures'
      return
    }
    const data = await response.json()
    this.fixtures = [...this.fixtures, ...data.fixtures]
    this.totalPages = data.totalPages
    if (this.hasMore) this.page += 1
  })

  @action
  setupSentinel(element) {
    this.observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && this.hasMore && !this.loadPage.isRunning) {
          this.loadPage.perform()
        }
      },
      { threshold: 0.5 }
    )
    this.observer.observe(element)
  }

  @action
  teardownSentinel() {
    this.observer?.disconnect()
  }

  constructor(owner, args) {
    super(owner, args)
    this.loadPage.perform()
  }

  <template>
    <div class="max-w-xl mx-auto p-4">
      <h2 class="font-bold text-gray-800 text-lg mb-4">📅 Fixtures</h2>
      <ul class="space-y-3">
        {{#each this.fixtures as |fixture|}}
          <li class="bg-white rounded-xl shadow-sm p-4">
            <div class="flex items-center justify-between">
              <div>
                <div class="font-medium text-gray-800">{{fixture.homeTeam}} vs {{fixture.awayTeam}}</div>
                <div class="text-xs text-gray-400 mt-0.5">{{fixture.venue}} • {{fixture.date}}</div>
              </div>
              <div class="text-xs px-2 py-1 rounded-full bg-gray-100 text-gray-500">{{fixture.format}}</div>
            </div>
          </li>
        {{/each}}
      </ul>
      {{#if this.loadPage.isRunning}}
        <div class="flex justify-center py-6">
          <div class="w-6 h-6 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      {{else if this.loadError}}
        <div class="text-red-500 text-sm text-center py-4">{{this.loadError}}</div>
      {{else if this.hasMore}}
        <div
          class="h-4"
          {{did-insert this.setupSentinel}}
          {{will-destroy this.teardownSentinel}}
        ></div>
      {{else}}
        <div class="text-center text-gray-400 text-sm py-6">All fixtures loaded</div>
      {{/if}}
    </div>
  </template>
}
```

An `IntersectionObserver` watches a sentinel `div` at the bottom of the list, triggering `loadPage` when it enters the viewport. The `drop` modifier prevents concurrent page loads when the user scrolls very fast. Each load appends new fixtures to the existing array and increments `page`. The sentinel div is only rendered when `hasMore` is true, automatically stopping observation when all pages are loaded.

