import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task, timeout } from 'ember-concurrency'

export default class AutocompletePlayerSearchComponent extends Component {
  @tracked query = ''
  @tracked suggestions = []
  @tracked showDropdown = false
  @tracked selectedPlayer = null
  @tracked activeIndex = -1

  @action
  updateQuery(event) {
    this.query = event.target.value
    this.showDropdown = true
    this.activeIndex = -1
    this.searchTask.perform(this.query)
  }

  @action
  selectPlayer(player) {
    this.selectedPlayer = player
    this.query = player.name
    this.showDropdown = false
    this.suggestions = []
    this.args.onSelect?.(player)
  }

  @action
  handleKeydown(event) {
    if (!this.showDropdown || !this.suggestions.length) return
    if (event.key === 'ArrowDown') {
      event.preventDefault()
      this.activeIndex = Math.min(this.activeIndex + 1, this.suggestions.length - 1)
    } else if (event.key === 'ArrowUp') {
      event.preventDefault()
      this.activeIndex = Math.max(this.activeIndex - 1, 0)
    } else if (event.key === 'Enter' && this.activeIndex >= 0) {
      this.selectPlayer(this.suggestions[this.activeIndex])
    } else if (event.key === 'Escape') {
      this.showDropdown = false
    }
  }

  @action
  handleBlur() {
    setTimeout(() => { this.showDropdown = false }, 150)
  }

  searchTask = task({ restartable: true }, async (query) => {
    await timeout(250)
    if (!query.trim()) {
      this.suggestions = []
      return
    }
    const response = await fetch(`/api/players/autocomplete?q=${encodeURIComponent(query)}&limit=6`)
    if (response.ok) this.suggestions = await response.json()
  })

  <template>
