import { task } from 'ember-concurrency'

export default class OptimisticLikeButtonComponent extends Component {
  @tracked isLiked = false
  @tracked count = 0
  @tracked likeError = null

  constructor(owner, args) {
    super(owner, args)
    this.isLiked = args.initialLiked ?? false
    this.count = args.initialCount ?? 0
  }

