import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, waitForEvent } from 'ember-concurrency'

const SHORTCUTS = {
  's': 'Save Score',
  'r': 'Refresh Data',
  'n': 'New Entry',
  'Escape': 'Close Modal'
}

export default class KeyboardShortcutHandlerComponent extends Component {
  @tracked activeShortcut = null
  @tracked lastTriggered = null

  executeAction(key) {
    switch(key) {
      case 's': this.args.onSave?.(); break
      case 'r': this.args.onRefresh?.(); break
      case 'n': this.args.onNew?.(); break
      case 'Escape': this.args.onClose?.(); break
    }
    this.lastTriggered = SHORTCUTS[key]
    setTimeout(() => { this.lastTriggered = null }, 2000)
  }

  listenTask = task(async () => {
    while (true) {
      const event = await waitForEvent(document, 'keydown')
      const key = event.key
      if (!SHORTCUTS[key]) continue
      if (event.target.tagName === 'INPUT' || event.target.tagName === 'TEXTAREA') continue
      event.preventDefault()
      this.activeShortcut = key
      this.executeAction(key)
      await new Promise(r => setTimeout(r, 200))
      this.activeShortcut = null
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.listenTask.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.listenTask.cancelAll()
  }

  <template>
    <div class="bg-white rounded-2xl shadow p-5 max-w-sm">
      <h3 class="font-bold text-gray-800 mb-3">⌨️ Keyboard Shortcuts</h3>
      <ul class="space-y-2">
        {{#each-in SHORTCUTS as |key label|}}
          <li class="flex items-center justify-between text-sm">
            <span class="text-gray-600">{{label}}</span>
            <kbd class="px-2 py-1 bg-gray-100 rounded text-xs font-mono border border-gray-300
              {{if (eq this.activeShortcut key) 'bg-blue-100 border-blue-400 text-blue-700'}}">
              {{key}}
            </kbd>
          </li>
        {{/each-in}}
      </ul>
      {{#if this.lastTriggered}}
        <div class="mt-3 text-xs text-green-600 text-center animate-pulse">⚡ {{this.lastTriggered}} triggered</div>
      {{/if}}
    </div>
  </template>
}
```

`waitForEvent` pauses the task until a DOM event fires, making the handler declarative and cancellation-safe. Input/textarea elements are excluded to allow normal typing. The 200ms delay after setting `activeShortcut` creates a visible highlight on the pressed key before resetting. Cancelling `listenTask` in `willDestroy` removes the event listener automatically, unlike `addEventListener` which requires manual cleanup.

