import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class ConnectionHealthCheckerComponent extends Component {
  @tracked isOnline = true
  @tracked latency = null
  @tracked consecutiveFails = 0
  CHECK_INTERVAL_MS = 5000

  get statusLabel() {
    if (!this.isOnline) return 'Offline'
    if (this.latency === null) return 'Checking...'
    if (this.latency < 100) return 'Excellent'
    if (this.latency < 300) return 'Good'
    return 'Slow'
  }

  get statusColor() {
    if (!this.isOnline) return 'bg-red-100 text-red-700'
    if (this.latency === null) return 'bg-gray-100 text-gray-500'
    if (this.latency < 100) return 'bg-green-100 text-green-700'
    if (this.latency < 300) return 'bg-yellow-100 text-yellow-700'
    return 'bg-orange-100 text-orange-700'
  }

  get dotColor() {
    if (!this.isOnline) return 'bg-red-500'
    if (this.latency === null) return 'bg-gray-400'
    if (this.latency < 300) return 'bg-green-500'
    return 'bg-orange-500'
  }

  healthTask = task(async () => {
    while (true) {
      const start = performance.now()
      try {
        const response = await fetch('/api/health', { method: 'HEAD', cache: 'no-store' })
        if (response.ok) {
          this.latency = Math.round(performance.now() - start)
          this.isOnline = true
          this.consecutiveFails = 0
        } else {
          throw new Error('Bad response')
        }
      } catch {
        this.consecutiveFails++
        if (this.consecutiveFails >= 2) this.isOnline = false
        this.latency = null
      }
      await timeout(this.CHECK_INTERVAL_MS)
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.healthTask.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.healthTask.cancelAll()
  }

  <template>
    <div class="inline-flex items-center gap-2 px-3 py-1.5 rounded-full {{this.statusColor}} text-xs font-medium">
      <span class="w-2 h-2 rounded-full {{this.dotColor}} {{if this.isOnline 'animate-pulse'}}"></span>
      <span>{{this.statusLabel}}</span>
      {{#if this.latency}}
        <span class="opacity-60">{{this.latency}}ms</span>
      {{/if}}
    </div>
  </template>
}
```

The health task uses `performance.now()` for high-precision latency measurement. Two consecutive failures are required before marking offline, preventing false positives from transient network blips. A `HEAD` request is used instead of `GET` to minimize bandwidth. The dot animates with `animate-pulse` only when online to provide a clear visual distinction from offline state.

