```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class CountdownToMatchComponent extends Component {
  @tracked secondsLeft = 0
  @tracked hasStarted = false
  @tracked isAlertShown = false

  get formattedTime() {
    if (this.hasStarted) return 'LIVE'
    const h = Math.floor(this.secondsLeft / 3600)
    const m = Math.floor((this.secondsLeft % 3600) / 60)
    const s = this.secondsLeft % 60
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`
  }

  get isImminent() {
    return this.secondsLeft <= 300 && !this.hasStarted
  }

  countdownTask = task(async () => {
    const startTime = new Date(this.args.matchStartTime).getTime()
    while (true) {
      const now = Date.now()
      const diff = Math.max(0, Math.floor((startTime - now) / 1000))
      this.secondsLeft = diff
      if (diff === 0 && !this.hasStarted) {
        this.hasStarted = true
        this.isAlertShown = true
        if ('Notification' in window && Notification.permission === 'granted') {
          new Notification('Match Starting!', { body: `${this.args.matchTitle} is now live!` })
        }
        return
      }
      await timeout(1000)
    }
  })

  constructor(owner, args) {
    super(owner, args)
    this.countdownTask.perform()
  }

  willDestroy() {
    super.willDestroy()
    this.countdownTask.cancelAll()
  }

  <template>
    <div class="bg-gray-900 text-white rounded-3xl p-8 text-center w-72">
      <p class="text-xs text-gray-400 uppercase tracking-widest mb-2">
        {{if this.hasStarted 'Match Status' 'Match starts in'}}
      </p>
      <div class="text-5xl font-bold font-mono mb-2
        {{if this.hasStarted 'text-green-400'
          (if this.isImminent 'text-red-400 animate-pulse' 'text-white')}}">
        {{this.formattedTime}}
      </div>
      <p class="text-sm text-gray-400">{{this.args.matchTitle}}</p>
      {{#if this.isAlertShown}}
        <div class="mt-4 bg-green-800 rounded-2xl px-4 py-3 text-green-300 text-sm font-semibold">
          🏏 Match has started!
        </div>
      {{/if}}
    </div>
  </template>
}
```

The countdown computes `secondsLeft` by diffing against the real clock each tick, avoiding drift that would accumulate with a simple decrement approach. The task exits (`return`) when the countdown reaches zero, stopping the loop automatically. `isImminent` triggers a red pulsing style in the final 5 minutes. `hasStarted` persists after the task exits so the LIVE state renders correctly.

