export default class CsvExporterComponent extends Component {
  @tracked isExporting = false
  @tracked exportSuccess = false
  @tracked exportError = null

  exportTask = task({ drop: true }, async () => {
    this.isExporting = true
    this.exportSuccess = false
    this.exportError = null
    const response = await fetch(
      `/api/matches/${this.args.matchId}/scorecard/csv`,
      { method: 'GET', headers: { Accept: 'text/csv' } }
    )
