import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class AudioCommentaryPlayerComponent extends Component {
  @tracked isPlaying = false
  @tracked isPaused = false
  @tracked streamError = null
  @tracked currentTrack = null
  audio = null

  get statusLabel() {
    if (this.setupTask.isRunning) return 'Connecting...'
    if (this.isPlaying) return 'Playing'
    if (this.isPaused) return 'Paused'
    return 'Stopped'
  }

  setupTask = task({ drop: true }, async () => {
    this.streamError = null
    const response = await fetch(`/api/matches/${this.args.matchId}/commentary/stream-url`)
    if (!response.ok) {
      this.streamError = 'Could not get stream URL'
      return
    }
    const { url, trackName } = await response.json()
    this.currentTrack = trackName
    if (this.audio) {
      this.audio.pause()
      this.audio = null
    }
    this.audio = new Audio(url)
    this.audio.onended = () => { this.isPlaying = false }
    this.audio.onerror = () => { this.streamError = 'Stream error'; this.isPlaying = false }
    await this.audio.play()
    this.isPlaying = true
    this.isPaused = false
  })

  @action
  play() {
    if (this.isPaused && this.audio) {
      this.audio.play()
      this.isPlaying = true
      this.isPaused = false
    } else {
      this.setupTask.perform()
    }
  }

  @action
  pause() {
    this.audio?.pause()
    this.isPlaying = false
    this.isPaused = true
  }

  @action
  stop() {
    this.audio?.pause()
    this.audio = null
    this.isPlaying = false
    this.isPaused = false
    this.currentTrack = null
  }

  willDestroy() {
    super.willDestroy()
    this.stop()
    this.setupTask.cancelAll()
  }

  <template>
