        <div class="text-red-400 text-xs text-center mt-2">{{this.streamError}}</div>
      {{/if}}
    </div>
  </template>
}
```

The `setupTask` fetches the stream URL and creates an `Audio` instance, playing it immediately. Resume from pause skips the task and calls `audio.play()` directly. `willDestroy` stops audio and cancels the setup task to prevent memory leaks and orphaned audio objects. The `drop` modifier prevents multiple simultaneous stream connections.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { action } from '@ember/object'
import { task } from 'ember-concurrency'

export default class DarkModePersistenceComponent extends Component {
  @tracked isDark = false
  @tracked saveError = null

  applyTheme(dark) {
    document.documentElement.classList.toggle('dark', dark)
  }

  loadPreference = task(async () => {
    const response = await fetch(`/api/users/${this.args.userId}/preferences`)
    if (!response.ok) return
    const { darkMode } = await response.json()
    this.isDark = darkMode ?? false
    this.applyTheme(this.isDark)
  })

  savePreference = task({ drop: true }, async (isDark) => {
    this.saveError = null
    const response = await fetch(`/api/users/${this.args.userId}/preferences`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ darkMode: isDark })
    })
    if (!response.ok) {
      this.saveError = 'Failed to save preference'
      this.isDark = !isDark
      this.applyTheme(this.isDark)
    }
  })

  @action
  toggleDarkMode() {
    this.isDark = !this.isDark
    this.applyTheme(this.isDark)
    this.savePreference.perform(this.isDark)
  }

  constructor(owner, args) {
    super(owner, args)
    this.loadPreference.perform()
  }

  <template>
    <div class="flex items-center gap-3">
      <span class="text-sm text-gray-600 dark:text-gray-300">{{if this.isDark 'Dark' 'Light'}} Mode</span>
      <button
        class="relative w-12 h-6 rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-blue-400
          {{if this.isDark 'bg-blue-600' 'bg-gray-300'}}"
        role="switch"
        aria-checked={{this.isDark}}
        {{on "click" this.toggleDarkMode}}
      >
        <span class="absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform
          {{if this.isDark 'translate-x-6'}}"></span>
      </button>
      <span class="text-lg">{{if this.isDark '🌙' '☀️'}}</span>
      {{#if this.saveError}}
        <span class="text-xs text-red-500">{{this.saveError}}</span>
      {{/if}}
    </div>
  </template>
}
```

The `applyTheme` method toggles the `dark` class on `documentElement`, enabling Tailwind's dark mode strategy. Theme is applied immediately on toggle before the API call for instant UI feedback, and rolled back if the save fails. The `loadPreference` task reads from the server on mount so user preferences survive across devices and sessions. The toggle uses ARIA `role=switch` and `aria-checked` for accessibility.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class RetryOnFailFetcherComponent extends Component {
  @tracked data = null
  @tracked attempts = 0
  @tracked hasGivenUp = false
  @tracked lastError = null
  MAX_RETRIES = 5
  BASE_DELAY_MS = 1000

  get statusMessage() {
    if (this.fetchTask.isRunning) return `Attempt ${this.attempts + 1} of ${this.MAX_RETRIES}...`
    if (this.hasGivenUp) return `Failed after ${this.MAX_RETRIES} attempts`
    if (this.data) return 'Data loaded successfully'
    return 'Click to load'
  }

  fetchTask = task(async () => {
    this.data = null
    this.hasGivenUp = false
    this.lastError = null
    for (this.attempts = 0; this.attempts < this.MAX_RETRIES; this.attempts++) {
      try {
        const response = await fetch(`/api/matches/${this.args.matchId}/scorecard`)
        if (!response.ok) throw new Error(`HTTP ${response.status}`)
        this.data = await response.json()
        return
      } catch (err) {
        this.lastError = err.message
        if (this.attempts < this.MAX_RETRIES - 1) {
          const delay = this.BASE_DELAY_MS * 2 ** this.attempts
          await timeout(delay)
        }
      }
    }
    this.hasGivenUp = true
  })

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <h2 class="font-bold text-gray-800 mb-4">📡 Scorecard Loader</h2>
      {{#if this.fetchTask.isRunning}}
        <div class="mb-4">
          <div class="flex justify-between text-xs text-gray-500 mb-1">
            <span>{{this.statusMessage}}</span>
            <span>{{this.attempts}} / {{this.MAX_RETRIES}}</span>
          </div>
          <div class="h-2 bg-gray-100 rounded-full overflow-hidden">
            <div
              class="h-full bg-blue-500 rounded-full transition-all"
              style={{concat "width: " (div (mul this.attempts 100) this.MAX_RETRIES) "%"}}
            ></div>
          </div>
          <div class="text-xs text-gray-400 mt-1 animate-pulse">Retrying with exponential backoff...</div>
        </div>
      {{else if this.hasGivenUp}}
        <div class="bg-red-50 rounded-xl p-4 mb-4">
          <div class="text-red-700 font-semibold text-sm">❌ Failed to load</div>
          <div class="text-red-500 text-xs mt-1">{{this.lastError}}</div>
        </div>
        <button
          class="w-full py-2 bg-red-600 text-white rounded-lg text-sm hover:bg-red-700"
          {{on "click" (perform this.fetchTask)}}
        >Try Again</button>
      {{else if this.data}}
        <div class="text-green-600 text-sm font-medium mb-3">✅ {{this.statusMessage}}</div>
        <div class="bg-gray-50 rounded-xl p-3 text-sm">
          <div class="font-medium">{{this.data.homeTeam}} vs {{this.data.awayTeam}}</div>
          <div class="text-gray-500 text-xs mt-1">{{this.data.result}}</div>
        </div>
      {{else}}
        <button
          class="w-full py-2 bg-blue-600 text-white rounded-lg text-sm hover:bg-blue-700"
          {{on "click" (perform this.fetchTask)}}
        >Load Scorecard</button>
      {{/if}}
    </div>
  </template>
}
```

Exponential backoff is calculated as `BASE_DELAY_MS * 2^attempt` — 1s, 2s, 4s, 8s — reducing server pressure during outages. The `for` loop increments `attempts` as a tracked property so the progress bar and status label update each attempt. After all retries are exhausted, `hasGivenUp` renders a failure state with a manual retry button.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class CircuitBreakerComponent extends Component {
  @tracked failCount = 0
  @tracked isOpen = false
  @tracked data = null
  @tracked lastError = null
  @tracked resetCountdown = 0
  FAIL_THRESHOLD = 3
  RESET_DELAY_MS = 10000

  get circuitState() {
    if (this.isOpen) return 'OPEN'
    if (this.failCount > 0) return 'HALF-OPEN'
    return 'CLOSED'
  }

  get stateColor() {
    const colors = { OPEN: 'text-red-600', 'HALF-OPEN': 'text-yellow-600', CLOSED: 'text-green-600' }
    return colors[this.circuitState]
  }

  resetTask = task(async () => {
    for (let i = this.RESET_DELAY_MS / 1000; i > 0; i--) {
      this.resetCountdown = i
      await timeout(1000)
    }
    this.isOpen = false
    this.failCount = 0
    this.resetCountdown = 0
  })

  fetchTask = task({ drop: true }, async () => {
    if (this.isOpen) return
    this.lastError = null
    try {
      const response = await fetch(`/api/matches/${this.args.matchId}/live-score`)
      if (!response.ok) throw new Error(`HTTP ${response.status}`)
      this.data = await response.json()
      this.failCount = 0
    } catch (err) {
      this.lastError = err.message
      this.failCount++
      if (this.failCount >= this.FAIL_THRESHOLD) {
        this.isOpen = true
        this.resetTask.perform()
      }
    }
  })

  <template>
    <div class="max-w-sm mx-auto bg-white rounded-2xl shadow p-6">
      <div class="flex items-center justify-between mb-4">
        <h2 class="font-bold text-gray-800">⚡ Live Score</h2>
        <div class="flex items-center gap-2">
          <span class="text-xs font-bold {{this.stateColor}}">{{this.circuitState}}</span>
          <span class="w-2 h-2 rounded-full
            {{if this.isOpen 'bg-red-500' (if this.failCount 'bg-yellow-400' 'bg-green-500')}}"></span>
        </div>
      </div>
      {{#if this.isOpen}}
        <div class="bg-red-50 border border-red-200 rounded-xl p-4 text-center mb-4">
          <div class="text-red-700 font-semibold text-sm">🔴 Circuit Open</div>
          <div class="text-red-500 text-xs mt-1">{{this.failCount}} failures detected</div>
          {{#if this.resetCountdown}}
            <div class="text-gray-500 text-xs mt-1">Auto-reset in {{this.resetCountdown}}s</div>
          {{/if}}
        </div>
      {{else if this.data}}
        <div class="text-center mb-4">
          <div class="text-4xl font-bold font-mono">{{this.data.runs}}/{{this.data.wickets}}</div>
          <div class="text-gray-400 text-sm">({{this.data.overs}} ov)</div>
        </div>
      {{/if}}
      {{#if this.lastError}}
        <div class="text-orange-500 text-xs mb-3">Last error: {{this.lastError}} ({{this.failCount}}/{{this.FAIL_THRESHOLD}} fails)</div>
      {{/if}}
      <button
        class="w-full py-2 bg-blue-600 text-white rounded-lg text-sm disabled:opacity-50 hover:bg-blue-700"
        disabled={{or this.isOpen this.fetchTask.isRunning}}
        {{on "click" (perform this.fetchTask)}}
      >
        {{if this.fetchTask.isRunning "Loading..." (if this.isOpen "Circuit Open" "Fetch Score")}}
      </button>
    </div>
  </template>
}
```

The circuit breaker pattern prevents repeated failed requests from overwhelming a struggling service. When `failCount` reaches `FAIL_THRESHOLD`, `isOpen` is set and `resetTask` starts a countdown timer. After the cooldown, the circuit resets to CLOSED and requests can retry. The `drop` modifier on `fetchTask` prevents queuing requests while the circuit is open.

```gjs
import Component from '@glimmer/component'
import { tracked } from '@glimmer/tracking'
import { task, timeout } from 'ember-concurrency'

export default class MatchSimulatorComponent extends Component {
  @tracked simulationLog = []
  @tracked step = 0
  @tracked isComplete = false
  @tracked totalSteps = 0

  get progress() {
    if (this.totalSteps === 0) return 0
    return Math.round((this.step / this.totalSteps) * 100)
  }

  simulateTask = task(async () => {
    this.simulationLog = []
    this.step = 0
    this.isComplete = false
    const planResponse = await fetch(`/api/matches/${this.args.matchId}/simulation-plan`)
    const plan = await planResponse.json()
    this.totalSteps = plan.deliveries.length
    for (const delivery of plan.deliveries) {
      await timeout(this.args.speedMs ?? 200)
      this.step++
      const entry = `Over ${delivery.over}.${delivery.ball}: ${delivery.batsman} — ${delivery.outcome}`
      this.simulationLog = [entry, ...this.simulationLog].slice(0, 50)
    }
    this.isComplete = true
  })

  <template>
    <div class="max-w-lg mx-auto bg-white rounded-2xl shadow p-6">
      <div class="flex items-center justify-between mb-4">
        <h2 class="font-bold text-gray-800 text-lg">🎮 Match Simulator</h2>
        {{#if this.simulateTask.isRunning}}
          <button
            class="px-3 py-1.5 bg-red-100 text-red-600 rounded-lg text-xs font-medium hover:bg-red-200"
            {{on "click" (fn this.simulateTask.cancelAll)}}
          >⏹ Cancel</button>
        {{/if}}
      </div>
      {{#if this.totalSteps}}
        <div class="mb-4">
          <div class="flex justify-between text-xs text-gray-500 mb-1">
            <span>Delivery {{this.step}} of {{this.totalSteps}}</span>
            <span>{{this.progress}}%</span>
          </div>
          <div class="h-2 bg-gray-100 rounded-full overflow-hidden">
            <div
              class="h-full bg-blue-500 transition-all duration-200 rounded-full"
              style={{concat "width: " this.progress "%"}}
            ></div>
          </div>
        </div>
      {{/if}}
      {{#if this.isComplete}}
        <div class="text-green-600 text-sm font-semibold mb-3">✅ Simulation complete!</div>
      {{/if}}
      <div class="bg-gray-900 text-green-300 rounded-xl p-4 font-mono text-xs h-48 overflow-y-auto">
        {{#if this.simulationLog.length}}
          {{#each this.simulationLog as |entry|}}
            <div class="mb-0.5">{{entry}}</div>
          {{/each}}
        {{else}}
          <div class="text-gray-500">Awaiting simulation...</div>
        {{/if}}
      </div>
      <button
        class="mt-4 w-full py-2 bg-blue-600 text-white rounded-lg font-semibold disabled:opacity-50 hover:bg-blue-700"
        disabled={{this.simulateTask.isRunning}}
        {{on "click" (perform this.simulateTask)}}
      >
        {{if this.simulateTask.isRunning "Simulating..." "Start Simulation"}}
      </button>
    </div>
  </template>
}
```

The task iterates over a server-provided delivery plan, adding a configurable delay between each step via `timeout()`. Calling `cancelAll()` from the cancel button immediately stops the loop at the next `await timeout`. The log prepends entries to always show the most recent delivery at the top, capped at 50 entries. `totalSteps` is fetched from the server so the progress bar accurately reflects the match length.
